function load_air_citys() {
    var ids = [];
    var eles = [];
    $('#EWA_LF_@sys_frame_unid .ewa-lf-data-row ').each(function() {
        var ser = $(this).find('#SER_ID');
        if (ser.attr("title") == '1') { //机票
            var eleDes = $(this).find('#SER_DES');
            var des = eleDes.text().split(' ')[0];
            var citys = des.split('_');
            ids.push(citys[0]);
            ids.push(citys[1]);
            eleDes.attr("f_city", citys[0]);
            eleDes.attr("t_city", citys[1]);
            eles.push(eleDes);
        }
    });

    if (ids.length == 0) {
        return;
    }

    var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
    u1.AddParameter("ewa_action", "ExtendAction0");
    u1.AddParameter("ewa_ajax", "json");
    u1.AddParameter("ids_split", ids.join(","));
    var u = u1.GetUrl();
    $J(u, function(rst) {
        var map = $J2MAP(rst, 'CITY_ID');
        for (var n in eles) {
            var d = eles[n];  

            var f_name = map[d.attr('f_city')].CITY_NAME;
            var t_name = map[d.attr('t_city')].CITY_NAME;

            d.text(f_name+"-"+t_name);

        }
    });
}
EWA.F.FOS["@sys_frame_unid"].ReloadAfter = function(httpReferer) {
    load_air_citys();
    var exp = "@@ENQ_JNY_PRICE * @@SUB_NUM = @@TOTAL (@@COIN_ID)";
    this.MergeExp('ENQ_JNY_PRICE', exp); //合并多个单元格

    var exp1 = "@@O_ENQ_JNY_PRICE_SUP * @@O_SUB_NUM = @@O_TOTAL (@@O_COIN_ID)";
    this.MergeExp('O_ENQ_JNY_PRICE_SUP', exp1, false, function(a) {
        var txt = a.text().trimEx();
        if (txt == "*  =  ()") {
            a.text("");
        }
    });  
};
EWA.F.FOS["@sys_frame_unid"].ReloadAfter();

(function() {
    let ewa=EWA.F.FOS["@sys_frame_unid"];
    var tb = $('#EWA_FRAME_@sys_frame_unid');

    let ext_enq_jny_ids="@ENQ_JNY_IDS".split(",");
    for(let i=0;i<ext_enq_jny_ids.length;i++){
        tb.find(".ewa-row-ENQ_JNY_IDS input[value='"+ext_enq_jny_ids[i]+"']").prop("checked",true);
    }


    var a = $("<a style='margin-left: 5px'>全选/全不选</a>");
    a.on('click', function() {
        var isSelectAll = tb.attr('selectall') == "1";
        if (isSelectAll) {
            tb.attr('selectall', 0);
        } else {
            tb.attr('selectall', 1);
        }
        tb.find(".ewa-row-ENQ_JNY_IDS input").prop("checked",!isSelectAll);
        // tb.find(".ewa-row-ENQ_JNY_IDS input").each(function() {
        //         this.checked = isSelectAll;
        // });
    });
    tb.find('.ewa-row-ENQ_JNY_IDS .EWA_TD_L').append(a).css('white-space', 'nowrap');
})();
/**
 * Frame 提交前进行检查，返回true，则可以提交数据
 * 同时可以手动增加提交的参数
 **/
EWA.F.FOS["@sys_frame_unid"].DoPostBefore = function() {
    var tb = $('#EWA_FRAME_@sys_frame_unid');
    if(!tb.find("#MEAL_ID").val()){
        if(!window.confirm("确定要删除勾选日期的含餐内容吗?")){
            return false;
        }
    }

    var add_data = {};
    var postData = this.CreatePostData();
    // 要复制到的日期
    add_data["enq_jny_id_split"] = postData.ENQ_JNY_IDS; 
    this.PostAddData = add_data;
    return true;
}

