Set.Bottom:
 function showAlert(r, color){
    $(r).find('td').css('background-color', color); 
 }
 /**
  * 调用本配置文件的 Action
  **/
 function loadActionJson_CheckCampStatus() {
     var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
     u1.AddParameter("ewa_action", "CheckCampStatus");
     u1.AddParameter("ewa_ajax", "json");
     var u = u1.GetUrl();
     $J(u, function(rst) {
         check_camp_status(rst);
     });
 }

 function check_camp_status(rst) {
     var camp_status = $('#CAMP_STAY_IN').val();
     var current_day = $('#ENQ_JNY_DAY').val();
     if (camp_status == '' && rst.length == 0) {
         window.camp_status_rst = true;
         return;
     }
     var is_have_start, is_have_end, middle;
     for (var n in rst) {
         var d = rst[n]; //数据行
         var st = n == current_day ? camp_status : d.CAMP_CLASS_TAG;
         // var name=d.NAME;
         if (st == 'CAMP_CLASS_CHECKIN') {
             is_have_start = n;
         } else if (st == 'CAMP_CLASS_CHECKOUT') {
             is_have_end = n;
         } else {
             middle = n;
         }
     }
     if (!is_have_start) {
         window.camp_status_rst[0] = false;
         window.camp_status_rst[1] = '没有设定入营日期, 点击确定继续，点击否修改';
         return;
     }

     if (is_have_end <= is_have_start) {
         window.camp_status_rst[0] = false;
         window.camp_status_rst[1] = '入营日期 > 离营日期, 点击确定继续，点击否修改';
         return;
     }

     if (middle < is_have_start) {
         window.camp_status_rst[0] = false;
         window.camp_status_rst[1] = '上课日期 > 入营日期, 点击确定继续，点击否修改';
         return;
     }
     if (current_day < is_have_end) {
         window.camp_status_rst[0] = false;
         window.camp_status_rst[1] = '离营之前要设定上课, 点击确定继续，点击否修改';
         return;
     }

     window.camp_status_rst[0] = true;
 }

