            }, 500);
        }
     }
     initTrans();

     function initJnyDesign(){
         var initData = {
             ways: "@WAY_CODE", //交通方式
             EWA_MTYPE: "@EWA_MTYPE",
             nums: "@nums", //总人数
             ttype: "@type",
             enq_sers: "@ids_split",
             num: "@num", // 人数
             head: "@head", //领队
             f_add: "@f_add",
             f_add_name: getObj('#F_ADD').text(),
             to_add: "@to_add",
             to_add_name: getObj('#TO_ADD').text(),
             to_add2:"@to_add2",
             to_add2_name: getObj('#TO_ADD2').text(),
             city_id:"@city_id",
             city_id_name: getObj('#CITY_ID').text(),
         };
         enqJnyDesignDj.init(ewa, initData);

         // 显示时程
         if("@EWA_MTYPE"=="M"){
            let src="@ewa.cp/business/group/enq-jny-day.jsp?grp_id=@grp_id&ENQ_JNY_ID=@ENQ_JNY_ID";
            let ifra="<iframe width='100%' height='500px' border='0' src='"+src+"' ></iframe>";
            $("#enq_jny_sers.sers@sys_frame_unid #z_tab4").html(ifra);
         }
     }
     if (window.enqJnyDesignDj) {
         initJnyDesign();
     } else {
         var t1 = window.setInterval(function() {
             if (window.enqJnyDesignDj) {
                 window.clearInterval(t1);
                 //enqJnyDesignDj.init(ewa);
                 initJnyDesign();
             }
         }, 20);
     }
 })();

