Set.Sql:
SELECT SER_ID,SER_NAME,SER_SCALE,SER_TAG FROM SER_MAIN WHERE SUP_ID=@G_SUP_ID -- 服务大类描述 ;
SELECT SER_ID , SER_CONN_ID , DBO.F_SER_DEP_LVL(@GRP_ID,SER_CONN_ID) AS SER_PRICE , COIN_ID , A.SUP_ID , SER_KEY0 , SER_KEY1 , SER_KEY2 , CITY_ID , SER_CONN_EDATE FROM SER_CONN A WHERE ( OWN_SUP_ID=@G_SUP_ID and SER_CONN_STATE='USED' and ( CITY_ID=@CITY_ID OR CITY_ID IN (SELECT COUNTRY_ID FROM CITY WHERE CITY_ID=@CITY_ID) ) and SER_CONN_EDATE >= getdate() ) or ser_conn_id in ( select ser_conn_id from ENQ_JNY_SER_SUB where enq_jny_id=@enq_jny_id and CITY_ID = @CITY_ID ) -- 城市下的所有服务 ;
SELECT SER_ID,SER_KEY_ID,ISNULL(SER_KEY_GRP,'') SER_KEY_GRP, SER_KEY_NAME,SER_KEY_REMARK,SER_KEY_DEF FROM SER_KEY WHERE OWN_SUP_ID=@G_SUP_ID AND SER_KEY_STATUS='USED' AND (SER_KEY_ID IN ( SELECT SER_KEY0 FROM SER_CONN A WHERE ( CITY_ID=@CITY_ID OR CITY_ID IN ( SELECT COUNTRY_ID FROM CITY WHERE CITY_ID=@CITY_ID) ) AND OWN_SUP_ID=@G_SUP_ID and SER_CONN_STATE='USED' and SER_CONN_EDATE >= getdate() UNION all SELECT SER_KEY1 FROM SER_CONN A WHERE CITY_ID=@CITY_ID AND OWN_SUP_ID=@G_SUP_ID and SER_CONN_STATE='USED' and SER_CONN_EDATE >= getdate() UNION select distinct ser_key0 from ENQ_JNY_SER_SUB WHERE enq_jny_id=@enq_jny_id UNION all select distinct ser_key1 from ENQ_JNY_SER_SUB WHERE enq_jny_id=@enq_jny_id ) -- OR (SER_KEY_EX1 = <at>CITY_ID) ) ORDER BY SER_KEY_GRP,SER_KEY_NAME ;
SELECT B.SUP_NAME,B.SUP_ID FROM SUP_MAIN B WHERE SUP_ID IN ( SELECT SUP_ID FROM SER_CONN A WHERE ( CITY_ID=@CITY_ID OR CITY_ID IN ( SELECT COUNTRY_ID FROM CITY WHERE CITY_ID=@CITY_ID ) ) AND OWN_SUP_ID=@G_SUP_ID and SER_CONN_STATE='USED' ) -- 服务下的供应商信息 ;
select SER_KEY_ID,SER_LGC_NUM0,SER_LGC_NUM1,SER_LGC_DY FROM SER_KEY_LOGIC WHERE SUP_ID=@G_SUP_ID AND SER_LGC_NUM0>=@NUMS;
select A.SER_ID, A.ENQ_JNY_SER_SUB_ID, A.ser_conn_id,B.SUP_ID AS sup_id, A.sup_down_id ,a.sub_num ,b.SER_KEY0, b.SER_KEY1, b.SER_KEY2,b.CITY_ID,a.enq_jny_price,a.ENQ_JNY_SER_REMARK from enq_jny_ser_sub A LEFT JOIN SER_CONN B ON A.SER_CONN_ID=B.SER_CONN_ID where a.enq_jny_id=@enq_jny_id and A.sup_id=@g_sup_id -- 已经保存的预算数据 ;
SELECT COIN_ID,COIN_NAME,COIN_KEY FROM SYS_COIN -- 货币信息 ;

