(function() {
    const serTagList = JSON.parse("@EWA.FRAME.DATA.ser_tag");
    const serTagsNameBySerId = $J2MAP1(serTagList, 'SER_ID,SER_TAG')
    console.log(serTagsNameBySerId);

    const serConns = JSON.parse("@EWA.FRAME.DATA.ser_conns");
    const serConnsByPurchaser = $J2MAP1(serConns, 'SER_ID,SUPPLY_SUP_ID')
    //console.log(serConnsByPurchaser);

    const enqJnySerSubs = JSON.parse("@EWA.FRAME.DATA.enq_jny_ser_subs");
    console.log(enqJnySerSubs);

    const head = '@head' * 1; //领队数量
    const num = '@NUM' * 1; //人数

    const ewa = EWA.F.FOS["@SYS_FRAME_UNID"];

    function getObj(exp) {
        return exp ? $('#EWA_LF_@SYS_FRAME_UNID').find(exp) : $('#EWA_LF_@SYS_FRAME_UNID');
    }
    ewa.AddPreRowCheck = function(tr, id, evt) {
        if (!ewa._showTimeBox) { //延时 100毫秒
            return;
        }
        if ("5" == $(tr).attr('ewa_key')) { //签证
            return;
        }
        var fo = evt.srcElement ? evt.srcElement : evt.target;
        console.log(fo);
        if (fo.tagName == 'TD' && $(fo).hasClass('ewa-col-TIME') || fo.id == "TIME") {
            return true;
        }
        return false;
    };
    setTimeout(function() { //延时 100毫秒
        ewa._showTimeBox = true;
    }, 1011);
    ewa.AddPreRowCloseEvent = function(frameUnid, cr, key, nr, evt) {
        const index = $(cr).parent().parent().attr('id').replace('t_tab', '') * 1; //t_tab0
        enqJnyDesign.sortByTimes(index)
    };

