            $(tr).after(newTr);
        }
        $(cntTd).css('background-color', 'lightblue');
        const cityId = $(tr).parent().parent().attr('cityid');
        const sup_id = $(tr).find('.ewa-col-SUPER select').val();
        const enq_jny_ser_sub_id = $(tr).attr('old_ser_sub_id');
