        u1.AddParameter('CITY_ID', cityId);
        u1.AddParameter('sup_id', sup_id || 0);
        u1.AddParameter('enq_jny_ser_sub_id', enq_jny_ser_sub_id || 0);
        u1.AddParameter('enq_jny_date', $('input#ENQ_JNY_DATE').last().val());
        u1.AddParameter('EWA_SKIP_TEST1', 1);
