        $Install(ajaxUrl, cntTd, function() {
            console.log('install ok');
        });
    });

    function appendTags(tr, index) {
        const serId = $(tr).attr('ewa_key');
        // console.log(serId, index);
        const tagSelect = $(tr).find('.ewa-col-TAG' + index + ' select');
        const list = serTagsNameBySerId[serId + ',TAG' + index];
        const name = serTagsNameBySerId[serId + ',NAME'][index];
        if (!name) {
            tagSelect.append(`<option value="" selected>-- N/A --</option>`);
            tagSelect.prop('disabled', true);
            return;
        }
        tagSelect.append(`<option value="">-- ${name.SER_TAG_NAME} --</option>`);
        list.forEach((v) => {
            const opt = $(`<option value='${v.SER_TAG_ID}'>${v.SER_TAG_NAME}</option>`);
            for (const key in v) {
                opt.attr(key, v[key]);
            }
            tagSelect.append(opt);
        });
    }
    ewa.tagChange = function(obj) {
        console.log(obj)

        const id = obj.id;
        if (id !== 'TAG0') {
            return;
        }
        const tr = $(getTr(obj));
        let tag0 = obj.value;
        for (let i = 1; i < 5; i++) {
            tr.find('.ewa-col-TAG' + i + ' option:gt(0)').each(function() {
                const parent = $(this).attr('ser_tag_parent');
                if (!parent || parent == "0") {
                    return;
                }
                if (tag0 == parent) {
                    $(this).show();
                } else {
                    $(this).hide();
                }
            });
        }
    };
    ewa.subNumChange = function(obj) {
        const subNum = obj.value;
        const tr = $(obj).parent().parent();
        const opt = tr.find('.ewa-col-PROVIDER option:selected');
        const total = opt.attr('para_ser_price') * subNum;
        const price = `${opt.attr('para_ser_price')*1}x${subNum}=${total}/${opt.attr('para_coin_key')}`;
        tr.find('.ewa-col-PRICE div').text(price);
    };
    ewa.providerChange = function(obj) {
        const tr = $(obj).parent().parent();
        let scale = tr.attr('data-ser-scale');
        scale = scale.replace('@@' + 'HEAD', head).replace('@@' + 'NUM', num);
        let subNum = Math.round(eval(scale));
        tr.find('#SUB_NUM').val(subNum)
        const opt = $(obj.options[obj.selectedIndex]);
        if (!opt.val()) {
            for (let i = 0; i < 5; i++) {
                let tagId = opt.attr('para_tag' + i);
                tr.find('.ewa-col-TAG' + i + ' select').val("");
            }
            tr.find('.ewa-col-SER_ID input').prop('checked', false);
            tr.find('.ewa-col-PRICE div').text("");
            tr.removeAttr('conn_ids');
            return;
        }
        for (let i = 0; i < 5; i++) {
            let tagId = opt.attr('para_tag' + i);
            //console.log(tagId, i);
            if (tagId > 0) {
                tr.find('.ewa-col-TAG' + i + ' select').val(tagId);
            }
        }
        const total = opt.attr('para_ser_price') * subNum;
        const price = `${opt.attr('para_ser_price')*1}x${subNum}=${total}/${opt.attr('para_coin_key')}`;
        tr.find('.ewa-col-PRICE div').text(price);
        tr.find('.ewa-col-SER_ID input').prop('checked', true);
        tr.attr('conn_ids', opt.attr('para_ser_conn_id'));
    };
    ewa.mDownAutoCheck = function(){
        return null; //禁止自动选择checkbox;
    }
    ewa.ReloadAfter = function(httpReferer) {
        // this.mergeHeaders('SUPER', '预算', 3); //合并单元格
        // this.mergeHeaders('ENQ_OP_MAIN', '服务采购', 3); //合并单元格

        getObj('.ewa-lf-data-row').each(function() {
            const serId = $(this).attr('ewa_key');
            const supSelect = $(this).find('.ewa-col-SUPER select');
            supSelect.append("<option value=''></option>")

            const providerMap = {};
            for (const k in serConnsByPurchaser) {
                if (k.split(',')[0] != serId) {
                    continue;
                }
                const v = serConnsByPurchaser[k];
                console.log(k, v);
                const providerId = v[0].SUPPLY_SUP_ID;
                if (providerMap[providerId]) {
                    continue;
                }
                providerMap[providerId] = true;
                const proivderSupName = v[0].SUPPLY_SUP_NAME;
                supSelect.append(`<option value=${providerId}>${proivderSupName}</option`);
            }
            for (let i = 0; i < 5; i++) {
                appendTags(this, i);
            }
        });

        // 显示enq_jny_ser_sub数据
        for (let i = 0; i < enqJnySerSubs.length; i++) {
            const d = enqJnySerSubs[i];
            console.log(d)
            let tr = getObj('tr[ewa_key="' + d.SER_ID + '"]');
            if (tr.length == 0) {
                console.log('not fund tr', d);
                continue;
            }
            if (tr.attr('seted')) {
                tr = copyRow(tr.find('.ewa-col-a div'))
            }
            tr.attr('seted', 1);
            const supplySupId = d.SUPPLY_SUP_ID;
            tr.attr('enq_jny_ser_sub', JSON.stringify(d))
            tr.find('#SUPER').val(supplySupId).trigger('change');

        }
    };

    ewa.supplyChange = function(obj) {
        const tr = $(obj).parent().parent();
        const providerSelect = tr.find('.ewa-col-PROVIDER select');
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "getProviders");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("ser_id", tr.attr('ewa_key'));
        u1.AddParameter('SUPPLY_SUP_ID', obj.value);
        let providerSupId = null;
        let json = null;
        if (tr.attr('enq_jny_ser_sub')) {
            json = JSON.parse(tr.attr('enq_jny_ser_sub'));
            providerSupId = json.PROVIDER_SUP_ID;
        }
        $J(u1, providerSelect[0], function(d) {
            const v = d.PROVIDER_SUP_NAME + ' ' + d.SER_KEY_NAME0 + '(' + d.SER_PRICE * 1 + ')';
            if (json && d.PROVIDER_SUP_ID == providerSupId) {
                setTimeout(function() { //根据服务修改价格/数量
                    const opt = tr.find('.ewa-col-PROVIDER option:selected');
                    opt.attr('para_ser_price', json.ENQ_JNY_PRICE);
                    tr.find('#SUB_NUM').val(json.SUB_NUM * 1).trigger('change');
                    tr.attr('old_ser_sub_id',  json.ENQ_JNY_SER_SUB_ID);
                }, 21);
            }
            return v;
        }, 'PROVIDER_SUP_ID', true, providerSupId);
    }
    ewa.ReloadAfter();
})();

