Set.Sql:
SELECT a.SER_ID, a.SER_PID, replace(a.SER_SCALE, '@', '@@') AS SER_SCALE, CASE WHEN @EWA_LANG = 'enus' THEN a.SER_NAME_EN ELSE a.SER_NAME END SER_NAME, a.SER_TAG FROM SER_MAIN a INNER JOIN ( SELECT ser_id FROM ser_conn WHERE ser_conn_ver = '2026' AND own_sup_id = @g_sup_id AND ser_conn_state = 'USED' AND SER_CONN_EDATE >= getdate() AND SER_CONN_SDATE <= getdate() AND city_id IN (@city_id, @COUNTRY_ID) UNION SELECT ser_id FROM enq_jny_ser_sub WHERE enq_jny_id = @enq_jny_id AND SER_CITY_ID IN (@city_id, @COUNTRY_ID) ) b ON a.ser_id = b.ser_id WHERE a.sup_id = 3 AND a.ser_lvl = 0 AND a.ser_ob3 = 'USED' ORDER BY a.ser_ord;
-- ewa_table_name ser_tag SELECT SER_ID, SER_TAG, SER_TAG_ID, SER_TAG_NAME, SER_TAG_NAME_EN, SER_TAG_PARENT FROM ser_tag WHERE SER_TAG_STATUS = 'USED' AND ( SER_TAG_CITY_ID IN (@city_id, @COUNTRY_ID) OR SER_TAG_CITY_ID IS NULL ) ORDER BY SER_ID, SER_TAG, SER_TAG_ORD;
-- ewa_table_name ser_conns SELECT DISTINCT SER_ID, SUPPLY_SUP_ID, SUPPLY_SUP_NAME FROM v_ser_conn_detail a WHERE ser_conn_ver = '2026' AND purchaser_sup_id = @g_sup_id AND ser_conn_state = 'USED' AND SER_CONN_EDATE >= getdate() AND SER_CONN_SDATE <= getdate() AND city_id IN (@city_id, @COUNTRY_ID);
-- ewa_table_name enq_jny_ser_subs SELECT * FROM enq_jny_ser_sub a INNER JOIN v_ser_conn_detail b ON a.ser_conn_id = b.ser_conn_id WHERE enq_jny_id = @enq_jny_id;

Set.Bottom:
function showDescription(uid, cr, key, nr, evt) {
    enqJnyDesign.showDescription(uid, cr, key, nr, evt);
}

function copyRow(obj) {
    const tr = getTr($(obj)[0]);
    let newtr = $(tr).clone(true, true);
    newtr.insertAfter(tr);
    newtr.removeAttr('enq_jny_ser_sub').removeAttr('conn_ids')
    return newtr;
}

function getTr(obj) {
    let p = obj;
    let inc = 0;
    while (p.tagName.toUpperCase() != 'TR') {
        p = p.parentNode;
        inc++;
        if (inc > 20) {
            return null;
        }
    }
    return p;
}

