(function(){
	let ewa = EWA.F.FOS['@SYS_FRAME_UNID'];
	ewa.ReloadAfter = function(httpReferer){
		if(httpReferer) { // 来源Frame的url，多出现在新增或修改后调用
			let uref = new EWA_UrlClass(httpReferer);
			let mtype   = uref.GetParameter("EWA_MTYPE");
			let refXml  = uref.GetParameter("XMLNAME");
			let refItem = uref.GetParameter("ITEMNAME");

			// frame定义了SQLSet的name以outParams开头的SELECT输出语句（大小写无关）
			let outParams = ewa.outParams; 
            if (outParams && outParams.length > 0) {
            	let outParam0 = outParams[0];
            }
		}
		// ewa.Merge('fromId', 'toId'); //合并单元格
		// let exp="@@aa <h1>@@bb</h1> <div>@@cc</div>";
		// ewa.MergeExp('toId', exp); //合并多个单元格
	};

	ewa.ext_AddNew = function(){
		let u1 = new EWA_UrlClass(ewa.Url);
		u1.RemoveEwa();
		u1.AddParameter("EWA_MTYPE","N");
		let paras = u1.GetParas();
		EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID','@xmlName', 'ENQ_JNY_SER_SUB.F.NM2025', false, paras);
	};

	function getObj(exp){
		return exp?$('#EWA_LF_@sys_frame_unid').find(exp):$('#EWA_LF_@sys_frame_unid');
	}

	// 执行刷新后事件
	function init(){
		ewa.ReloadAfter ();
	}
	init();
})();

(function() {
    let ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    //提交后台数据时执行的检查或附加数据处理
    ewa.DoPostBefore = function() {
        /*
		//附加数据处理
		// ewa.PostAddData = {add1:'a',add2:2};

        // 附加检查合法性
    	if(getObj('#aaa').val()==''){
    		return false; //检查不通过
    	}else{
    		return true; //检查通过
    	}
	    */
        return true;
    };

    function getObj(exp) {
        return $('#f_@sys_frame_unid').find(exp);
    }

    function init() {
        $('#f_@sys_frame_unid').parent().parent().css('overflow', 'hidden');
        const services = $('#EWA_LF_@from_unid .ewa-col-SER_NAME');
        services.each(function() {
            if(!this.dataset.serId){
                return;
            }
            const enqJnySerSubId = this.dataset.enqJnySerSubId;
            const refTr = $(this).closest('tr');
            const tr = refTr.clone();
            tr.removeAttr('onmousedown')
            tr.find('td').each(function() {
                const text = $(this).text().trim();
                if(!text){
                    $(this).remove();
                } else {
                    $(this).text(text);
                }
            });
            const id = 'sel_'+enqJnySerSubId;
            tr.find('td:eq(0)').html(`<input value=${enqJnySerSubId} type=checkbox id=${id}>`)
            const label = $('<label></label>');
            label.attr('for', id);
            label.append(tr);
            getObj('#services').append(label);
        });

        getObj('#butClose').on('click', function(){
            window.seviceSelectDialog.Close();
        });
        getObj('#butOk').on('click', function(){
            const ids =[];
            getObj('input[type=checkbox]:checked').each(function(){
                ids.push(this.value);
            })  ;        
            if(ids.length == 0){
                $Tip('请先选择服务');
                return;
            }
            EWA.F.FOS["@from_unid"].moveServices(ids.join(','), "@enq_jny_day_id");
        });
    }
    init();
})();

