        });
    }

    let root = "@ewa.cp/business/group/enq-jny-settings.jsp?" + $U();
    ewa.ReloadAfter = function(isFirst) {
        setTimeout(showPois, 1);
        loadActionJson_modifyLogs();

        let t = setInterval(function() {
            if (typeof enqJnySettings == 'undefined') {
                return;
            }
            window.clearInterval(t);
            ewa._settings = new enqJnySettings(root, getObj(), true);
            ewa._settings.init("@MODE" != 'ENQ_DESGIN_LIST')
        }, 10);

        // var tb = $('#EWA_LF_@sys_frame_unid');
        // var s = "<div><a onclick='EWA.F.FOS[\"@sys_frame_unid\"].changeImage(this)'>更改</a>" +
        //     " <a onclick='EWA.F.FOS[\"@sys_frame_unid\"].setImageAsCover(this)'>设为封面</a>" +
        //     " <a onclick='EWA.F.FOS[\"@sys_frame_unid\"].deleteImage(this)'>删除</a></div>";
        // if (isEn) {
        //     s = "<div><a onclick='EWA.F.FOS[\"@sys_frame_unid\"].changeImage(this)'>Change</a>" +
        //         " <a onclick='EWA.F.FOS[\"@sys_frame_unid\"].setImageAsCover(this)'>Set as Cover</a>" +
        //         " <a onclick='EWA.F.FOS[\"@sys_frame_unid\"].deleteImage(this)'>Delete</a></div>";
        // }
        // tb.find(".EWA_GRID_BG_IMG").each(function() {
        //     if ($(this).attr('ori_src').indexOf('transparent.png') > 0) {
        //         $(this).attr('onclick', 'EWA.F.FOS["@sys_frame_unid"].changeImage(this)');
        //     } else {
        //         $(this).attr('onclick', 'EWA.F.FOS["@sys_frame_unid"].openImage(this)');
        //     }
        //     $(this).parent().append(s);
        // });
    };
    ewa.ReloadAfter(1);

    function createPicBox(d) {
        const piUnid = d.PI_UNID;
        const intro = d.PI_SUMMARY.replace(/</ig, '&lt;').replace(/>/ig, '&gt;');
        const html = `<div class='poi'>
                        <div class='name'>
                            <a onclick='showPoiInfo("${piUnid}")'>${d.PI_NAME}</a> ${d.PI_RATING * 1}/5
                        </div>
                        <div class='pics'></div>
                        <div class='intro'>${intro}</div>
                    </div>`;
        return html;
    }

    function createPic(p) {
        const bg = `@ewa.cp/robert/v.jsp?tb=poi_pic&inline=1&pp_unid=${p.PP_UNID}&resize=320x240`;
        const pic = `<a class='pic' onclick='showPoiInfo("${p.PI_UNID}")'
                    style='background-image:url(${bg})'></a>`;
        return pic;
    }

    function showPics(pois, poiPics, key, key1) {
        const pics = {};
        for (let n in pois) {
            let d = pois[n]; //数据行
            const id = d[key] + (key1 ? ',' + d[key1] : ''); //.SER_CONN_ID;
            pics[id] = {
                html: createPicBox(d),
                images: []
            };
        }
        for (let i = 0; i < poiPics.length; i++) {
            const p = poiPics[i];
            const id = p[key] + (key1 ? ',' + p[key1] : ''); //.SER_CONN_ID
            if (pics[id].images.length >= 4) {
                continue;
            }
            pics[id].images.push(createPic(p));
        }
        console.log(pics);
        for (const id in pics) {
            const box = $(pics[id].html);
            box.find('.pics').append(pics[id].images.join(''));
            const tr = 'SER_CONN_ID' == key ? getObj('tr[data-ser-conn-id="' + id + '"]') :
                getObj('tr[ewa_key="' + id.split(',')[0] + '"]');
            tr.find('.event-content').append(box);
        }
    }

    function loadActionJson_GetPois(ids) {
        if (ids.length == 0) {
            return;
        }
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.AddParameter("xmlname", "/front-web/study-tour/web.xml");
        u1.AddParameter('ITEMNAME', "2025_ENQ_JNY.Lf.v");
        u1.AddParameter("enq_id", "@enq_id");
        u1.AddParameter("ewa_action", "GetPois");
        u1.AddParameter("ewa_ajax", "json_all");
        const data = {
            "ids_split": ids
        };
        let u = u1.GetUrl();
        $JP1(u, data, function(rst) {
            const pois = rst[0];
            const poiPics = rst[1];

            // ENQ_JNY_DAY_POI 中设定的景点
            const poisByDay = rst[2];
            const poiPicsByDay = rst[3];
            showPics(pois, poiPics, 'SER_CONN_ID');
            showPics(poisByDay, poiPicsByDay, 'ENQ_JNY_DAY_ID', 'PI_UNID');

        });
    }

    function showPois() {
        const nav = `<div id='days'>
    <div id="days-nav" class="big" style="top:0px;padding:10px;position: sticky">
    </div>
</div>`;
        $('#days').remove();
        let g = $('#_G_@sys_frame_unid');
        if (g.length == 0) {
            g = $('#days-detail');
        }
        console.log('g=', g);
        g.find('div:eq(0)').css('flex', 1);
        g.css({
            display: 'flex'
        }).prepend(nav).attr('id', 'days-detail');

        let ss = [];
        $('#days-detail .ewa-lf-data-row .ewa-col-ENQ_JNY_DAY').each(function() {
            let tmpId = EWA_Utils.tempId('enq');
            $(this).find('span').attr('rid', tmpId);
            ss.push($(this).html());
        });
        $('#days-nav').append(ss.join(""));
        if (ss.length <= 14) {
            $('#days-nav').addClass('big');
        }
        $('#days-nav span').on('click', function() {
            let rid = $(this).attr('rid');
            let target = $('#days-detail span[rid="' + rid + '"]').last();
            let top = target.offset().top;
            document.documentElement.scrollTo(0, top - 100);
        });

        getObj('[id=times]').each(function() {
            $(this).find('.evt').last().addClass('evt-last');
        });
        const ids = [];
        getObj('tr[data-ser-id]').each(function() {
            ids.push(this.dataset.serConnId);
        });
        loadActionJson_GetPois(ids);
    };

})();

