Set.Sql:
INSERT INTO ENQ_JNY ( SUP_ID, ADM_ID, ENQ_ID, GRP_ID, TRAFFIC, ENQ_JNY_CONTENT, JNY_CATEGORY, ENQ_JNY_DAY, ENQ_JNY_DATE, WAY_CODE, F_ADD, TO_ADD, TO_ADD2, CITY_ID, ENQ_JNY_FORM_ID, ENQ_JNY_CDATE ) SELECT @g_sup_id, @g_adm_id, @enq_id, @grp_id, 'AIR', '出发前', '', 0, a.F_DATE - 1, '', a.F_CITY, 0, 0, 0, -1, @sys_date FROM enq_main a WHERE 1=2 and enq_id = @enq_id AND NOT EXISTS ( SELECT 1 FROM enq_jny WHERE enq_id = @enq_id AND ENQ_JNY_DAY = 0 );
-- EWA_SQL_SPLIT_NO SELECT FLOW_STATE FROM ENQ_MAIN a INNER JOIN grp_main gm ON a.grp_id = gm.grp_id WHERE a.ENQ_ID = @ENQ_ID AND gm.GRP_RUN_MODEL = 'GRP_RUN_SINGLE' -- 散拼可以改，要改航班和日期，2025-01-22，吕国芳 ;
SELECT e1.*, @EWA.PATH_UPLOAD_URL + PM.PIC_PATH + '$resized/320x240.jpg' AS ENQ_PIC, HOTEL.SER_KEY_NAME AS HOTEL_NAME, MEAL.SER_KEY_NAME AS MEAL_NAME, BUDGET.BUDGET, CONVERT(VARCHAR, e1.ENQ_JNY_DATE, 112) DT -- 用于营地课程关联 FROM ENQ_JNY e1 LEFT JOIN PIC_MAIN PM ON PM.REF_ID = E1.ENQ_jny_ID AND PM.REF_TAG = 'ENQ_JNY' AND PM.PIC_STATUS = 'WEB_NWS_DLV' LEFT JOIN SER_KEY HOTEL ON E1.HOTEL_ID = HOTEL.SER_KEY_ID LEFT JOIN SER_KEY MEAL ON E1.MEAL_ID = MEAL.SER_KEY_ID LEFT JOIN ( -- 预算 SELECT ENQ_JNY_ID EJ, SUM(A * ISNULL(C.GRP_POINT, 1)) BUDGET FROM ( SELECT C.GRP_ID, C.ENQ_ID, A.ENQ_JNY_ID, COIN_ID, SUM(ENQ_JNY_PRICE * SUB_NUM) A FROM ENQ_JNY_SER_SUB A INNER JOIN ENQ_JNY B ON A.ENQ_JNY_ID = B.ENQ_JNY_ID INNER JOIN ENQ_MAIN C ON B.ENQ_ID = C.ENQ_ID WHERE C.GRP_ID > 0 AND C.SUP_ID = @G_SUP_ID AND C.ENQ_STATE = 'USED' AND ( C.enq_id = @enq_id OR ( ( @enq_id = '' OR @enq_id IS NULL ) AND C.enq_select_state = 'CHECKED_TRUE' AND C.GRP_ID = @GRP_ID AND C.SUP_ID = @G_SUP_ID ) ) GROUP BY C.GRP_ID, C.ENQ_ID, A.ENQ_JNY_ID, COIN_ID ) A INNER JOIN GRP_MAIN B ON A.GRP_ID = B.GRP_ID LEFT JOIN GRP_COIN C ON C.GRP_ID = B.GRP_ID AND B.GRP_COIN = C.COIN_TO AND A.COIN_ID = C.COIN_FROM GROUP BY ENQ_JNY_ID ) BUDGET ON E1.ENQ_JNY_ID = BUDGET.EJ WHERE e1.enq_id = @enq_id AND e1.sup_id = @g_sup_id ORDER BY e1.ENQ_JNY_DAY

DELETE FROM ENQ_JNY WHERE ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

delete from ENQ_JNY_SER where ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

delete from ENQ_JNY_SER_SUB where ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

exec PR_ENQ_FEE @enq_id;

exec PR_ENQ_TO_PRICE @ENQ_ID;

UPDATE  ENQ_JNY SET ENQ_JNY_FORM_ID = -1 -- 借用， 0表示删除
    WHERE ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID
;

delete from ENQ_JNY_SER where ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY 
        where ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id) 
    AND SUP_ID=@G_SUP_ID;

delete from ENQ_JNY_SER_SUB 
where ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY 
        where ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id)
    AND SUP_ID=@G_SUP_ID;

DELETE FROM ENQ_JNY WHERE ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id AND SUP_ID=@G_SUP_ID;

exec PR_ENQ_FEE @enq_id;

exec PR_ENQ_TO_PRICE @ENQ_ID;

select 1 DEL_OK;

