Set.Bottom:
function showAlert(r, color) {
    $(r).find('td').css('background-color', color);
}
/**
 * 调用本配置文件的 Action
 **/
function loadActionJson_CheckCampStatus() {
    var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
    u1.AddParameter("ewa_action", "CheckCampStatus");
    u1.AddParameter("ewa_ajax", "json");
    var u = u1.GetUrl();
    $J(u, function(rst) {
        check_camp_status(rst);
    });
}

function check_camp_status(rst) {
    var camp_status = $('#CAMP_STAY_IN').val();
    var current_day = $('#ENQ_JNY_DAY').val();
    if (camp_status == '' && rst.length == 0) {
        window.camp_status_rst = true;
        return;
    }
    var is_have_start, is_have_end, middle;
    for (var n in rst) {
        var d = rst[n]; //数据行
        var st = n == current_day ? camp_status : d.CAMP_CLASS_TAG;
        // var name=d.NAME;
        if (st == 'CAMP_CLASS_CHECKIN') {
            is_have_start = n;
        } else if (st == 'CAMP_CLASS_CHECKOUT') {
            is_have_end = n;
        } else {
            middle = n;
        }
    }
    if (!is_have_start) {
        window.camp_status_rst[0] = false;
        window.camp_status_rst[1] = '没有设定入营日期, 点击确定继续，点击否修改';
        return;
    }

    if (is_have_end <= is_have_start) {
        window.camp_status_rst[0] = false;
        window.camp_status_rst[1] = '入营日期 > 离营日期, 点击确定继续，点击否修改';
        return;
    }

    if (middle < is_have_start) {
        window.camp_status_rst[0] = false;
        window.camp_status_rst[1] = '上课日期 > 入营日期, 点击确定继续，点击否修改';
        return;
    }
    if (current_day < is_have_end) {
        window.camp_status_rst[0] = false;
        window.camp_status_rst[1] = '离营之前要设定上课, 点击确定继续，点击否修改';
        return;
    }

    window.camp_status_rst[0] = true;
}

(function() {
    var ewa = EWA.F.FOS["@sys_frame_unid"];
    ewa.DoPostBefore = function() {
        return true;
    };
    function getObj(exp) {
        return exp ? $('#f_@sys_frame_unid').find(exp) : $('#f_@sys_frame_unid');
    }
    ewa.doPostAfter = function() {
        if ("@from_pid") { // 刷新列表
            EWA.F.FOS["@from_pid"].Reload();
        }
    };
    function initTrans() {
        const box = $(`<div style="display: flex">
            <div class='cn'><div ></div><div></div></div>
            <div class='en'><div ></div><div></div></div>
        </div>`);
        box.find('.cn div:eq(0)').append(getObj('.ewa-tr-summary.ewa-row-ENQ_JNY_CONTENT'));
        box.find('.cn div:eq(1)').append(getObj('#ENQ_JNY_CONTENT'));
        box.find('.en div:eq(0)').append(getObj('.ewa-tr-summary.ewa-row-ENQ_JNY_CONTENT_EN'));
        box.find('.en div:eq(1)').append(getObj('#ENQ_JNY_CONTENT_EN'));
        getObj('tbody:eq(0)').append(box);
    }
    initTrans();
    let box = $('#main_@sys_frame_unid');

    function initJnyDesign() {
        var initData = {
            ways: "@WAY_CODE", //交通方式
            EWA_MTYPE: "@EWA_MTYPE",
            nums: "@nums", //总人数
            ttype: "@type",
            enq_sers: "@ids_split",
            num: "@num", // 人数
            head: "@head", //领队
            readOnly: "@hide".toUpperCase() === "YES", // 只读模式
            enqJnyDay: '@ENQ_JNY_DAY',
            // opType: "@OP_TYPE",
            isEn: 'enus' == EWA.LANG,
            costCampInfo: {
                costCampId: "@cost_camp_id",
                camp0KeyId: "@camp0_key_id",
                CO_STUDENT: '@CO_STUDENT' * 1,
                CO_CS: '@CO_CS' * 1,
                CO_CS_MEDIA: "@CO_CS_MEDIA" * 1,
                CO_CS_MEDICAL: "@CO_CS_MEDICAL" * 1,
                CO_FOREIGN_TEACHER: "@CO_FOREIGN_TEACHER" * 1,
                CO_CHINES_TEACHAR: "@CO_CHINES_TEACHAR" * 1
            }
        };

        if ("@cost_camp_id") {
            let s = "学生: @CO_STUDENT, 外教: @CO_FOREIGN_TEACHER，中教: @CO_CHINES_TEACHAR，" +
                "辅导员: @CO_CS，媒体: @CO_CS_MEDIA，医疗: @CO_CS_MEDICAL";
            if ('enus' == EWA.LANG) {
                s = "Students: @CO_STUDENT, Foreign teachers: @CO_FOREIGN_TEACHER, Chinese teachers: @CO_CHINES_TEACHAR," +
                    "Counselors: @CO_CS, Medias: @CO_CS_MEDIA, Medicals: @CO_CS_MEDICAL";
            }
            getObj('.ewa-row-NUMS .EWA_TD_M').append("<span>(" + s + ")</span>");
        } else {
            let s = '领队：@head_num, 学生: @people_num';
            if ('enus' == EWA.LANG) {
                s = 'Leaders: @head_num, Students: @people_num';
            }
            getObj('.ewa-row-NUMS .EWA_TD_M').append("<span>(" + s + ")</span>");
        }
        enqJnyDesign.init(ewa, initData);

        // 显示时程
        if ("@EWA_MTYPE" == "M") {

        } else {
            enqJnyDesign.setCityId(1);
        }
    }
    if (window.enqJnyDesign) {
        // 异步加载 js
        initJnyDesign();
    } else {
        var t1 = window.setInterval(function() {
            if (window.enqJnyDesign) {
                window.clearInterval(t1);
                //enqJnyDesign.init(ewa);
                initJnyDesign();
            }
        }, 20);
    }

    if ("@OP_TYPE" == "SUPPLY" || "@OP_TYPE" == "UNKNOW") {
        box.find("#bt_saveinfo,#butCopyServices,#butOk,hr").hide();
        box.find('.ewa-row-ENQ_JNY_CONTENT_EN a:eq(0)').trigger('click');
        getObj('input,select').prop('disabled', true);
        getObj('textarea').prop('readOnly', true);
        //box.find('#tab7').trigger('click').show();
    }
    if ("@OP_TYPE" == "SELF") {
        //box.find('#tab5,#tab6').show();
    }
    if ("@EWA_MTYPE" == "M") {
        box.find('#tab5,#tab6,#tab7').show();
        $("#enq_jny_sers.sers@sys_frame_unid #tab4").show();
    }
    if ("@FLOW_STATE" == "ENQ_END") {
        box.find("#bt_saveinfo,#butCopyServices").hide();
    }
})();

