function reload_day_des() {
    var u = EWA.CP + "/EWA_STYLE/cgi-bin/?xmlname=" + "@xmlname".toURL() +
        "&itemname=ENQ_JNY.Frame.NewModify";
    u += "&EWA_ACTION=GetDayDes&EWA_AJAX=json&" + $U();
    u += "&CITY_ID=" + lastCityId;
    var tr = EWA.F.FOS[ser_main_check_unid].prevTr;

    $(tr).find('iframe').animate({
            height: 0
        },
        343,
        function() {
            tr.style.display = 'none';
            tr.cells[0].innerHTML = "";
            EWA.F.FOS[ser_main_check_unid].prevTr = null;
        });

    $J(u, function(v) {
        g_day_des[lastIdx] = v;
        loadDayDes(lastIdx); //define in enq_rob.js
    });
}

