Set.Bottom:
(function() {
    const flightsInfo = JSON.parse("@EWA.FRAME.DATA.flightsInfo");
    console.log(flightsInfo)
    const ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    ewa.getObj = function(exp) {
        var tb = $('#EWA_FRAME_' + this._Id);
        if (exp) {
            // 改写，用于刷新供应商
            return tb.find(exp).length == 0 ? $('#option_@SYS_FRAME_UNID').find(exp) : tb.find(exp);
        } else {
            return tb;
        }
    };

    function getCtripCaptureJs() {
        const url = "/static/prj/from-page/ctrip/get-flights-from-order.js?r=" + Math.random();
        const root = "@EWA.HOST_BASE" + "back_admin/apis/revice-flights-from-ctrip-order.jsp?ref_tag=" + ewa.ctripRefTag;
        $J2(url, function(rst) {
            rst = rst.replace('[WEB_ROOT]', root);
            ewa.ctripJs = rst;
        });
    }

    function checkCtripData() {
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "getCtripFlightData");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("ref_tag", ewa.ctripRefTag);

        let cheked = false;
        $Tip('请在浏览器的携程机票订单控制台下粘贴代码，系统会自动获取数据', () => {
            return cheked
        })
        const t = window.setInterval(() => {
            $J1(u1, function(rst) {
                if (rst.length == 0) {
                    return;
                }
                window.clearInterval(t);
                // console.log(rst[0]);
                cheked = true;
                showCtripFlights(rst[0]);

            });
        }, 1000);
    }

    function showCtripFlights(result) {
        $('#ctrip-@sys_frame_unid').hide();

        const flights = JSON.parse(result.FlightOfferJSON);
        // 单价
        $('#option_@sys_frame_unid #GRP_AM_UNIT').val(flights.totalPrice);

        const segments = flights.segments;
        let tbodies = getObj('tbody')
        for (let i = 0; i < segments.length; i++) {
            if (tbodies[i]) {
                $(tbodies[i]).show();
            }
        }

        for (let i = tbodies.length; i < segments.length; i++) {
            addFlight(true);
        }
        tbodies = getObj('tbody');
        for (let i = 0; i < segments.length; i++) {
            const segment = segments[i];
            console.log(segment);

            const tbody = $(tbodies[i]);
            tbody.find('#GRP_AIR_CODE').val(segment.flightNo);
            tbody.find('#GRP_AIR_TIME').val(segment.departureTime);
            tbody.find('#GRP_AR_TIME').val(segment.arrivalTime);
            tbody.find('#GRP_AR_MID').val(segment.transfer);
            tbody.find('#GRP_AIR_MEMO').val(segment.description);
            tbody.find('#GRP_AR_FA').val(segment.fromAirport);
            tbody.find('#GRP_AR_TA').val(segment.toAirport);

            segment._tbody = tbody;


            const enqJnyDay = tbody.find('#ENQ_JNY_DAY');
            const dCity = tbody.find('#GRP_AIR_CITY_ID');
            const aCity = tbody.find('#GRP_AR_CITY_ID');
            segment._dCity = dCity;
            segment._aCity = aCity;

            enqJnyDay.find('option:gt(0)').each(function() {
                const json = JSON.parse($(this).attr('json'));
                if (json.enq_jny_date.indexOf(segment.departureDate) === 0) {
                    this.selected = true;
                    segment._enq_jny_day = this.value;
                    segment._json = json;
                    return;
                }
            });
            enqJnyDay.trigger('change');
        }
        let completedInc = 0;
        const t = setInterval(() => {
            for (i = 0; i < segments.length; i++) {
                const segment = segments[i];
                if (segment._showCitys || segment._dCity[0].options.length == 0 ||
                    segment._aCity[0].options.length == 0) {
                    continue;
                }
                segment._showCitys = true;
                completedInc++;
                // 出发城市
                showCity(segment._dCity[0], segment.fromCity);
                // 抵达城市
                showCity(segment._aCity[0], segment.toCity);
            }
            if (completedInc == segments.length) {
                console.log('showCity completed');
                window.clearInterval(t);
            }
        }, 101);
    }

    function showCity(select, cityName) {
        //console.log(cityName);
        for (let i = 1; i < select.options.length; i++) {
            const opt = select.options[i];
            if (opt.text == cityName) {
                opt.selected = true;
                return true;
            }
        }
        return false;
    }
    ewa.copyJs = function() {
        return navigator.clipboard.writeText(ewa.ctripJs).then(() => {
            $Tip('脚本复制完成');
            checkCtripData();
            return true;
        }).catch(err => {
            alert('Copy failed:', err);
        });
    };

    ewa.DoPostBefore = function() {
        const GRP_AIR_LVL = $('#option_@SYS_FRAME_UNID #GRP_AIR_LVL').val();
        const GRP_AIR_NUM = $('#option_@SYS_FRAME_UNID #GRP_AIR_NUM').val();
        const GRP_AIR_TICKET_TYPE = $('#option_@SYS_FRAME_UNID #GRP_AIR_TICKET_TYPE').val();
        const GRP_AM_UNIT = $('#option_@SYS_FRAME_UNID #GRP_AM_UNIT').val();
        const GRP_AM_SUPID = $('#option_@SYS_FRAME_UNID #GRP_AM_SUPID').val();
        if (!GRP_AM_SUPID) {
            $Tip('请选择供应商');
            return;
        }
        if (!GRP_AM_UNIT) {
            $Tip('请填写单价或填为0');
            return;
        }
        if (!GRP_AIR_TICKET_TYPE) {
            $Tip('请选择出票类别');
            return;
        }
        if (!GRP_AIR_LVL) {
            $Tip('请选择舱位');
            return;
        }
        if (!GRP_AIR_NUM) {
            $Tip('请输入数量');
            return;
        }
        const flights = [];
        let isok = true;
        getObj('tbody:visible').each(function() {
            const rowData = {
                GRP_AIR_NUM,
                GRP_AIR_LVL,
                GRP_AIR_TICKET_TYPE
            };
            flights.push(rowData);
            $(this).find('input,select').each(function() {
                // console.log(this);
                const tr = $(this).parent().parent();
                const name = $(this).attr('name');
                const val = $(this).val();
                if (!val && tr.hasClass('ewa-row-must')) {
                    $Tip('需要完整输入');
                    $Mark(this);
                    isok = false;
                }
                rowData[name] = val;
            });
        });
        const data = {
            GRP_AM_UNIT,
            GRP_AM_SUPID,
            flights: JSON.stringify(flights)
        };
        console.log(data);
        //附加数据处理
        // ewa.PostAddData = {add1:'a',add2:2};
        const url = "@ewa.cp/business/group/enq-flights.jsp?" + $U();
        let aaa = false;
        $Tip('处理中...', () => {
            return aaa
        });
        $JP(url, data, (rst) => {
            aaa = true;
            if (!rst.RST) {
                alert(rst.ERR);
                return;
            }
            EWA.F.FOS["@from_unid"].Reload();
            window.seviceSelectDialog.Close();
            window.seviceSelectDialog = null;
        });
        return false;
    };

    function getObj(exp) {
        return exp ? $('#f_@sys_frame_unid').find(exp) : $('#f_@sys_frame_unid');
    }

    function addFlight(showRemove) {
        const clone = getObj('tbody:eq(0)').clone(true);
        clone.find('.ewa-frame-buttons').remove();
        if (showRemove) {
            clone.find('.ewa-row-remove a').show();
        }
        clone.find('input,select').val("");
        getObj('.ewa-frame').append(clone);
    }

    function showEnqJnyFlights() {
        if (flightsInfo.length == 0) {
            return;
        }
        console.log('showEnqJnyFlights')
        $('#main_@sys_frame_unid').addClass('modify');
        if (flightsInfo.length == 1) {
            $('#option_@sys_frame_unid #single').trigger('click');
        } else if (flightsInfo.length == 2) {
            $('#option_@sys_frame_unid #return').trigger('click');
        } else {
            $('#option_@sys_frame_unid #multi').trigger('click');
        }

        showTbodiesByCount(flightsInfo.length);
        for (let i = 0; i < flightsInfo.length; i++) {
            const flight = flightsInfo[i];
            const tbody = $(getObj('tbody')[i]);
            for (const k in flight) {
                const obj =  tbody.find('#' + k);
                const v = flight[k];
                obj.val(v);
                if('GRP_AIR_CITY_ID' == k){ //出发
                    flight._dCity = obj;
                    flight.fromCity = v;
                } else  if('GRP_AR_CITY_ID' == k){//抵达
                    flight._aCity = obj;
                    flight.toCity = v;
                } else if('ENQ_JNY_DAY' == k){
                    obj.trigger('change');
                }
            }
        }

        let completedInc = 0;
        const t = setInterval(() => {
            for (i = 0; i < flightsInfo.length; i++) {
                const segment = flightsInfo[i];
                if (segment._showCitys || segment._dCity[0].options.length == 0 ||
                    segment._aCity[0].options.length == 0) {
                    continue;
                }
                segment._showCitys = true;
                completedInc++;
                console.log(segment);
                // 出发城市
                segment._dCity.val(segment.fromCity);
                // 抵达城市
                segment._aCity.val(segment.toCity);
            }
            if (completedInc == flightsInfo.length) {
                console.log('showCity completed');
                window.clearInterval(t);
            }
        }, 101);
    }
    /**
     * 根据数量显示/隐藏 tbody 元素（不足则新增，多余则隐藏）
     */
    function showTbodiesByCount(count) {
        if (count < 1) {
            console.warn('[showTbodiesByCount] count 应 ≥ 1，已修正为 1');
            count = 1;
        }
        let $tbodies = getObj('tbody');
        // --- 步骤1：补足数量（若不足）---
        while ($tbodies.length < count) {
            addFlight(true); // 允许删除
            $tbodies = getObj('tbody'); // 重新获取
        }
        // --- 步骤2：显示前 count 个，隐藏其余 ---
        $tbodies.each((index, el) => {
            const $el = $(el);
            if (index < count) {
                $el.show();
            } else {
                $el.hide();
            }
        });
        return $tbodies.filter(':lt(' + count + ')'); // 返回已显示的 tbody
    }

    function init() {
        ewa.ctripRefTag = crypto.randomUUID();
        ewa.ctripRefTag = '745b8db9-dded-457c-8229-6061dcbab88e'; //测试用
        getCtripCaptureJs();

        if (!getObj('.ewa-row-GRP_AIR_NUM input').val()) {
            getObj('.ewa-row-GRP_AIR_NUM input').val("@NUMS");
        }

        $('#option_@sys_frame_unid').append(getObj('.ewa-row-GRP_AM_SUPID'));
        //出票类别TAG3
        $('#option_@sys_frame_unid').append(getObj('.ewa-row-GRP_AIR_TICKET_TYPE'));
        //舱位 TAG4
        $('#option_@sys_frame_unid').append(getObj('.ewa-row-GRP_AIR_LVL'));
        // 数量
        $('#option_@sys_frame_unid').append(getObj('.ewa-row-GRP_AIR_NUM'));
        $('#option_@sys_frame_unid').append(getObj('.ewa-row-GRP_AM_UNIT'));

        getObj('#butAdd').on('click', function() {
            if ($('#option_@sys_frame_unid input[type=radio]:checked').val() == 'multi') {
                addFlight(true);
            } else {
                $Tip('请切换到多程')
            }
        });
        $('#option_@sys_frame_unid input[type=radio]').on('click', function() {
            getObj('tr').removeClass('ctrip')
            getObj('tbody').show();
            $('#ctrip-@sys_frame_unid').hide();
            if (this.value == 'single') {
                getObj('tbody:gt(0)').hide();
            } else if (this.value == 'return') {
                getObj('tbody:gt(1)').hide();
            } else if (this.value == 'ctrip') {
                getObj('tr').addClass('ctrip')
                getObj('tbody').hide();
                $('#ctrip-@sys_frame_unid').show();
                const ctripSupId = 3147;
                ewa.refreshDropList('GRP_AM_SUPID', ctripSupId);
            }
        });
        getObj('#ENQ_JNY_DAY').on('change', function() {
            const tbody = $(this).parent().parent().parent();
            const departure = tbody.find('#GRP_AIR_CITY_ID')[0];
            const arrival = tbody.find('#GRP_AR_CITY_ID')[0];
            const inputDate = tbody.find('#GRP_AIR_DATE');
            if (!this.value) {
                departure.innerHTML = "";
                arrival.innerHTML = "";
                inputDate.val("");
                return;
            }

            const json = JSON.parse($(this).find('option:selected').attr('json'));
            const date = json.enq_jny_date.split(' ')[0];
            inputDate.val(date);

            const u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
            u1.AddParameter("ewa_action", "SAct0");
            u1.AddParameter("ewa_ajax", "json");
            u1.AddParameter("ENQ_JNY_DAY", this.value);

            // departure city
            departure.options.length = 0;
            $J(u1, departure, 'CITY_NAME', 'CITY_ID', true, '@GRP_AIR_CITY_ID');
            // arrival city
            arrival.options.length = 0;
            $J(u1, arrival, 'CITY_NAME', 'CITY_ID', true, '@GRP_AR_CITY_ID');
        });
        getObj('.ewa-row-remove a').hide();
        addFlight();
        addFlight();
        $('#option_@sys_frame_unid input[type=radio]:eq(1)').trigger('click');

        showEnqJnyFlights();
    }
    init();
})();

