(function() {
    const ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    //提交后台数据时执行的检查或附加数据处理
    ewa.DoPostBefore = function() {
        return true;
    };

    function getObj(exp) {
        return exp ? $('#f_@sys_frame_unid').find(exp) : $('#f_@sys_frame_unid');
    }
    ewa.searchFlightNo = function() {
        const flightNo = getObj('#GRP_AIR_CODE').val();
        if (!flightNo) {
            $Tip('请输入航班号');
            return;
        }
        const u = "@ewa.cp/back_admin/apis/flights.jsp?flight_nos=" + flightNo +
            '&date=' + getObj('#GRP_AIR_DATE').val();
        let isok = false;
        $Tip('查询航班信息...', () => {
            return isok
        });
        $J(u, function(rst) {
            isok = true;
            console.log(rst);
            if (!rst.RST) {
                alert(rst.ERR + '<br>请检查航班号或修改查询日期');
                return;
            }
            ewa.refreshDropList('GRP_AIR_CITY_ID', rst.from_city_id);
            ewa.refreshDropList('GRP_AR_CITY_ID', rst.to_city_id);
            getObj('#GRP_AIR_MEMO').val(rst.descriptions);
            getObj('#GRP_AIR_TIME').val(rst.fist_depture_time)
            if(rst.last_arrival_time){
                getObj('#GRP_AR_TIME').val(rst.last_arrival_time)
            } else {
                const lastFlight = rst.flights[rst.flights.length - 1];
                getObj('#GRP_AR_TIME').val(lastFlight.a_scheduled_time);
            }

            getObj('#GRP_AR_FA').val(getAirPort(rst, 'departure'));
            getObj('#GRP_AR_TA').val(getAirPort(rst, 'arrival'));
            getObj('#GRP_AR_MID').val(getAirPort(rst, ""));
        });
    };

    function getAirPort(rst, qtype) {
        // routes[ "PEK",  "HAK",  "LHR"]
        const routes = rst.routes;
        // iatas { "HAK": "美兰机场",  "PEK": "首都机场",  "LHR": "希思罗机场"}
        const iatas = rst.iatas;
        if (qtype == 'departure') {
            const iata = routes[0];
            return iatas[iata];
        } else if (qtype == 'arrival') {
            const iata = routes[routes.length - 1];
            return iatas[iata];
        }
        const ss = [];
        for (let i = 1; i < routes.length - 1; i++) {
            const iata = routes[i];
            const des = iatas[iata];
            ss.push(des);
        }
        return ss.join('/');
    }

    function installFlightNo() {
        const exp = `<table><tr>
            <td>@@GRP_AIR_CODE</td>
            <td><a onclick="EWA.F.FOS['@sys_frame_unid'].searchFlightNo()">查询航班信息</a></td></table>`;
        ewa.MergeExp('GRP_AIR_CODE', exp);
    }

    function init() {
        installFlightNo();
    }
    init();
})();

