EWA.F.FOS["@sys_frame_unid"].batModify = function() {
    let ids = [];
    let id = -1;
    var tb = $('#EWA_LF_@sys_frame_unid');
    $("#EWA_LF_@sys_frame_unid>tbody>tr>td>input[name='ENQ_JNY_ID']:checked").each(function() {
        ids.push($(this).val());
    });
    let paras = "ENQ_ID=@ENQ_ID&ENQ_JNY_ID_FROM=" + ids[0];
    if (ids.length > 0) {
        paras += "&ENQ_JNY_IDS=" + ids.join(",");
    }
    EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid", "/business/enq/enqJnyDesign.xml", "ENQ_JNY.F.batModify", false, paras);
}

EWA.F.FOS["@sys_frame_unid"].batDelete = function() {
    let ids = [];
    $("#EWA_LF_@sys_frame_unid>tbody>tr.ewa-lf-data-row").each(function() {
        if ($(this).find("input[name='ENQ_JNY_ID']:checked").length > 0) {
            ids.push($(this).attr("ewa_key"));
        }
    });
    if (ids.length == 0) {
        return;
    }
    var paras = [];
    paras[0] = {
        Name: 'IDS_SPLIT',
        Value: ids.join(",")
    };
    EWA.F.FOS["@sys_frame_unid"].DoAction(this, "batDelJny", "确认删除吗?", "", paras);
}

