    Reload: function() {
        top.$Tip("添加成功");
        EWA.F.FOS["@sys_frame_unid"].enq_jny_canup1();
        window.setTimeout(function() {
            EWA.F.FOS["@sys_frame_unid"].Reload();
        }, 500);
    }
}

EWA.F.FOS["@sys_frame_unid"].changeImage = function(obj) {
    var u = new EWA_UrlClass("@ewa.cp/robert/ewa.jsp");
    u.AddParameter("XMLNAME", "@xmlname");
    u.AddParameter("ITEMNAME", "PIC_MAIN.LF.M_PIC_LIB");
    u.AddParameter("IMG_RADIO", "1");
    u.AddParameter("POP_SELECT", "1");
    u.AddParameter("PIC_LIB", "ENQ_JNY_PIC_LIB");

    var tr = $(obj).parentsUntil('tbody').last();
    var enq_jny_id = tr.attr('ewa_key');
