    //加载修改记录
    function loadActionJson_modifyLogs() {
        console.log('loadActionJson_modifyLogs（修改记录）')
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "modifyLogs");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("EWA_JSON_FIELD_CASE", "lower");

        let u = u1.GetUrl();
        $J(u, function(rst) {
            for (let n in rst) {
                let d = rst[n]; //数据行
                let tr = getObj(`tr[data-enq-jny-day=${d.enq_jny_day}]`);
                let s = `<a style='padding-left:4px; font-weight:bold' 
                    onclick='EWA.F.FOS["@SYS_FRAME_UNID"].viewModfyLogs(${d.enq_jny_day})'>修改记录(${d.changes})</a>`
                tr.find('.ewa-col-CITY_ID .s1').append(s)
            }
        });
    }

    let root = "@ewa.cp/business/group/enq-jny-settings.jsp?" + $U();
    ewa.ReloadAfter = function(isFirst) {
        loadActionJson_modifyLogs();

        getObj().parent().attr("id", 'days').addClass('list-all');
        getObj('tbody').attr('id', 'days-detail');
        if (getObj('.ewa-col-SERS').length > 0) {
            getObj().addClass('have-sers');
        }
        EWA_Utils.LazyBackgroundLoad();

        var exp0 = isEn ? "<div>Budget: <span>@@BUDGET</span> CNY</div> @@SERS" : "<div>预算：<span>@@BUDGET</span>元</div> @@SERS";
        this.MergeExp('SERS', exp0, false, function(td, tr) {});



        let t = setInterval(function() {
            if (typeof enqJnySettings == 'undefined') {
                return;
            }
            window.clearInterval(t);

            ewa._settings = new enqJnySettings(root, getObj(), true);
            ewa._settings.init("@MODE" != 'ENQ_DESGIN_LIST')
        }, 10);

        var tb = $('#EWA_LF_@sys_frame_unid');
        var s = "<div><a onclick='EWA.F.FOS[\"@sys_frame_unid\"].changeImage(this)'>更改</a>" +
            " <a onclick='EWA.F.FOS[\"@sys_frame_unid\"].setImageAsCover(this)'>设为封面</a>" +
            " <a onclick='EWA.F.FOS[\"@sys_frame_unid\"].deleteImage(this)'>删除</a></div>";
        if (isEn) {
            s = "<div><a onclick='EWA.F.FOS[\"@sys_frame_unid\"].changeImage(this)'>Change</a>" +
                " <a onclick='EWA.F.FOS[\"@sys_frame_unid\"].setImageAsCover(this)'>Set as Cover</a>" +
                " <a onclick='EWA.F.FOS[\"@sys_frame_unid\"].deleteImage(this)'>Delete</a></div>";
        }
        tb.find(".EWA_GRID_BG_IMG").each(function() {
            if ($(this).attr('ori_src').indexOf('transparent.png') > 0) {
                $(this).attr('onclick', 'EWA.F.FOS["@sys_frame_unid"].changeImage(this)');
            } else {
                $(this).attr('onclick', 'EWA.F.FOS["@sys_frame_unid"].openImage(this)');
            }
            $(this).parent().append(s);
        });

        //移动checkbox
        $("#EWA_LF_@sys_frame_unid>tbody>tr.ewa-lf-data-row>.ewa-col-ENQ_JNY_DAY").each(function() {
            $(this).append($(this).prev().find("input"));
        });
        if(ewa._lastFocusEnqJnyId){
            getObj('tr[ewa_key="'+ewa._lastFocusEnqJnyId+'"]').trigger('mousedown');
            ewa._lastFocusEnqJnyId = null;
        }
    };
    $(window).on('scroll', function() {
        EWA_Utils.LazyBackgroundLoad();
    });

    ewa.ReloadAfter(1);

})();

