Set.Bottom:
//ENQ_JNY_SER_SUB_FLIGHT.LF.M
(function() {
    const ewa = EWA.F.FOS['@SYS_FRAME_UNID'];
    ewa.ReloadAfter = function(httpReferer) {
        getObj('tr.ewa-lf-data-row').each(function() {
            const eaEnqJnyId = this.dataset.eaEnqJnyId;
            if (eaEnqJnyId) {
                $(this).find('#EA_ENQ_JNY_ID').val(eaEnqJnyId);
            }
        });
        if ("@enq_jny_ids") {
            const ids = "@enq_jny_ids".split(',');
            const sortList = [];
            getObj('select#EA_ENQ_JNY_ID:eq(0) option:gt(0)').each(function() {
                for (let i = 0; i < ids.length; i++) {
                    if (ids[i] == this.value) {
                        sortList.push(this.value);
                    }
                }
            });
            console.log(ids, sortList)
            for (let i = 0; i < sortList.length; i++) {
                getObj('select#EA_ENQ_JNY_ID:eq(' + i + ')').val(sortList[i]);
            }
        }
        
        if('@auto_select') {
            //自动选择，参数 auto_select
            ewa.ext_set ();
        }
    };
    ewa.ext_set = function() {
        let isok = true;
        const aIds = [];
        const eaEnqJnyIds = [];
        const eaIds = [];
        getObj('select#EA_ENQ_JNY_ID').each(function() {
            if (!this.value) {
                $Tip('请选择日程');
                $Mark(this);
                isok = false;
            }
            const tr = $(this).parent().parent()[0];
            const departureCity = tr.dataset.aDCityId
            const arrivalCity = tr.dataset.aACityId

            const opt = this.options[this.selectedIndex];
            const json = JSON.parse($(opt).attr('json'));

            const enqDepartureCity = json.f_add
            const enqDepartureCity1 = json.to_add
            const enqDepartureCity2 = json.to_add2

            if (departureCity != enqDepartureCity && departureCity != enqDepartureCity1 && departureCity != enqDepartureCity2) {
                $Tip('日程(' + opt.text + ')出发城市有误');
                $Mark(this);
                isok = false;
            }

            const enqArrivalCity = json.city_id;
            const enqArrivalCity1 = json.to_add;
            const enqArrivalCity2 = json.to_add2;
            if (enqArrivalCity != arrivalCity && enqArrivalCity1 != arrivalCity && enqArrivalCity2 != arrivalCity) {
                $Tip('日程(' + opt.text + ')抵达城市有误');
                $Mark(this);
                isok = false;
            }

            const aId = tr.dataset.aId;
            const eaId = tr.dataset.eaId || -1;
            const eaEnqJnyId = this.value;

            aIds.push(aId);
            eaIds.push(eaId);
            eaEnqJnyIds.push(eaEnqJnyId);
        });

        if (!isok) {
            return;
        }
        const data = {
            aIds: aIds.join(','),
            eaIds: eaIds.join(','),
            eaEnqJnyIds: eaEnqJnyIds.join(',')
        };
        // 安全创建 Url 类
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "UAct0");
        u1.AddParameter("ewa_ajax", "json");
        let u = u1.GetUrl();
        $JP(u, data, function(rst) {
            const pewa = EWA.F.FOS["@from_unid_1"];
            const obj = $('input[obj_rid="@obj_rid"]');
            console.log(obj);
            // 再次触发选择服务
            pewa.ext_select(obj[0], true); //skipFlightSetDate
            pewa.flightSetDateDia.Close();
        });
    };
    ewa.ext_NewOrModifyOrCopy = function(mtype, pkParas) {
        const u1 = new EWA_UrlClass(ewa.Url);
        u1.RemoveEwa();
        u1.AddParameter("EWA_MTYPE", mtype);
        // 指定是否在固定高度窗口打开，窗口内容会自适应滚动
        // u1.AddParameter("EWA_IN_DIALOG", "1");
        let paras = u1.GetParas();
        if (pkParas) {
            paras += '&' + pkParas;
        }
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '@xmlName', 'ENQ_JNY_SER_SUB_FLIGHT.F.NM', false, paras);
    };

    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }

    // 执行刷新后事件
    function init() {
        ewa.ReloadAfter();
    }
    init();
})();

