select '无权限' EWA_ERR_OUT where not exists( select 1 from enq_main a inner join enq_jny b on a.enq_id=b.enq_id inner join share_data sd on sd.sd_tag = 'GRP_MAIN' and a.grp_id=sd.grp_id and SD_DATA = @G_SUP_ID where b.enq_jny_id=@TO_ENQ_JNY_ID ) ;
SELECT case when gm.GRP_STA='SCM_GRP_STA_UNENQ' then '已成团不能修改' else '审批流程已到等待客户确认，不能修改' end EWA_ERR_OUT FROM ENQ_MAIN em INNER JOIN ENQ_JNY ej ON ej.ENQ_ID = em.ENQ_ID INNER JOIN GRP_MAIN gm ON em.GRP_ID = gm.GRP_ID WHERE ej.ENQ_JNY_ID = @TO_ENQ_JNY_ID AND (em.FLOW_STATE IN ('ENQ_END', 'ENQ_CONTRACT_VALID','ENQ_CUS_YES') or gm.GRP_STA='SCM_GRP_STA_UNENQ') -- AND gm.GRP_RUN_MODEL = 'GRP_RUN_SINGLE' -- 散拼可以改，要改航班和日期，2025-01-22，吕国芳 ;
select top 1 '不能导入，请先删除已有服务项目' EWA_ERR_OUT from ENQ_JNY_SER a where ENQ_JNY_ID = @to_enq_jny_id and @IMPORT_TYPES like '%SER_ITEMS%' ;
delete ENQ_JNY_DAY where ENQ_JNY_ID=@TO_ENQ_JNY_ID and @DEL_TIMES='COM_YES' ;
update ENQ_JNY_SER_SUB set ENQ_JNY_SER_SUB_TMP_RID=null where ENQ_JNY_ID=@TO_ENQ_JNY_ID and @DEL_TIMES='COM_YES' ;
exec PR_ENQ_JNY_SUB_IMPORT @TO_ENQ_JNY_ID,@FROM_ENQ_JNY_ID,@G_SUP_ID,@G_ADM_ID,@IMPORT_TYPES

Set.Bottom:
(function() {
    let ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    const ptr = getObj().parent().parent().prev();
    ewa.DoPostBefore = function() {
        const des = createDescription();
        if (ewa._init_des == des) {
            return;
        }
        ewa.PostAddData = {
            'EDJ_REMARK': des,
            "ENQ_JNY_DAY_ID": "@ENQ_JNY_DAY_ID"
        }
        return true;
    };

    function getObj(exp) {
        return exp ? $('#f_@sys_frame_unid').find(exp) : $('#f_@sys_frame_unid');
    }

    function createDescription() {
        const ss = [];
        const time0 = getObj('#EJD_TIME_BEGIN').val();
        const time1 = getObj('#EJD_TIME_END').val();
        const timeType = getObj('#EJD_TIME_BUCKET option:selected').text();
        if (time0 && time1) {
            ss.push(time0 + '-' + time1);
        } else if (time0 || time1) {
            ss.push(time0 || time1);
        } else {
            ss.push(timeType);
        }
        const serDes = getObj("#EJD_SER_TAG_DES option:selected").text();
        if (serDes) {
            ss.push(serDes);
        }
        if ("1" == "@ser_id") {
            const airlines = getObj('#EDJ_AIRLINES').val();
            ss.push('航班: ' + airlines)
        }
        const timeSpan = getObj('#EJD_TIME_SPAN').val();
        if (timeSpan) {
            ss.push('时长: ' + timeSpan + '小时');
        }
        const guide = getObj('#GUIDES').val();
        if (guide) {
            ss.push('导游: ' + guide);
        }
        const place0 = getObj('#EDJ_PLACE_BEGIN').val();
        const place1 = getObj('#EDJ_PLACE_END').val();
        if (place0 && place1) {
            ss.push('出发地点：' + place0 + "，抵达：" + place1);
        } else if (place0) {
            ss.push('地点：' + place0);
        } else if (place1) {
            ss.push('地点：' + place1);
        }
        const distance = getObj('#EJD_TRANSPORT_DISTANCE').val();
        if (distance) {
            ss.push('距离：' + distance + '公里');
        }
        let text = ss.join('，');

        const des = getObj('#EDJ_DESC').val();
        if (des) {
            text += '\n' + des;
        }

        return text;
    }

    function change() {
        const desc = createDescription();
        const data = ewa.createPostData();
        console.log(data);
        ptr.attr('time', JSON.stringify(data));
        ptr.find('#TIME').text(desc).attr('title', desc);

        ewa.DoPost();
    }

    function loadActionJson_addrs() {
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);

        u1.AddParameter("ewa_action", "SAct0");
        u1.AddParameter("ewa_ajax", "json");

        let u = u1.GetUrl();

        $J(u, function(rst) {
            const ss = ['<datalist id="addrs" >'];
            for (let n in rst) {
                let d = rst[n]; //数据行
                let s = `<option value="${d.addr}"></option>`;
                ss.push(s)
            }
            ss.push('</datalist>');
            getObj().append(ss.join(''));

            getObj('#EDJ_PLACE_BEGIN,#EDJ_PLACE_END').attr('list', 'addrs');
        });

    }

    function aiDistance() {
        const prompt = getObj('#EDJ_PLACE_BEGIN').val() + " 到 " + getObj('#EDJ_PLACE_END').val();
        const u = "@ewa.cp/back_admin/ai/stream.jsp?MODE=getdistance" +
            "&request_id=" + crypto.randomUUID() +
            "&mode=getdistance&prompt=&ai_model=qwen-plus&ai_provider=qwen&ai_thinking=false" +
            "&prompt=" + prompt.toURL();
        $J(u, function(rst) {
            if (!rst.RST) {
                alert(rst.ERR);
                return;
            }
            let content = rst.content;
            if (content.indexOf('```json') >= 0) {
                content = content.split('```json')[1];
                content = content.split('```')[0];
            }
            const json = JSON.parse(content);
            getObj('#EJD_TRANSPORT_DISTANCE').val(json.distance);
            getObj('#EJD_TIME_SPAN').val(json.time);

            //console.log(rst);
            change();
        });
    }

    function airlinesSearch() {
        const flight_nos = getObj('#EDJ_AIRLINES').val().replace('/', ',').replace('-', ',').replace('+', ',');
        const u = "@ewa.cp/back_admin/apis/flights.jsp?flight_nos=" + flight_nos.toURL() +
            "&date=@enq_jny_date";
        $J(u, function(rst) {
            if (!rst.RST) {
                alert(rst.ERR);
                return;
            }
            let flights = rst.flights;

            console.log(flights)
            const ss = [];
            flights.forEach((flight, index) => {
                const depTime = flight.d_scheduled_time;
                const arrTime = flight.a_scheduled_time;
                const depAddr = `${flight.d_airport_name}（${flight.d_airport_code}）${flight.d_terminal}航站楼`;
                const arrAddr = `${flight.a_airport_name}（${flight.a_airport_code}）${flight.a_terminal}航站楼`;
                if (0 == index) {
                    getObj('#EDJ_PLACE_BEGIN').val(depAddr);
                }
                getObj('#EDJ_PLACE_END').val(arrAddr);
                description = (flights.length == 1 ? "" : `${index+1}. `) +
                    `${flight.flight_number} ${depAddr}于${depTime}出发，于${arrTime}抵达${arrAddr}，飞行时长${flight.duration}。`;
                if (index > 1) {
                    description += `待机时间：${flight.layover_time}。`;
                }
                ss.push(description);

            });
            getObj('#EDJ_DESC').val(ss.join('\n'));
            getObj('#EJD_TIME_BEGIN').val(rst.fist_depture_time);
            getObj('#EJD_TIME_END').val(rst.last_arrival_time);
            getObj('#EJD_TIME_SPAN').val(rst.total_time);
        });
    }

    function init() {
        const u0 = new EWA_UrlClass(ewa.Url);
        u0.AddParameter('itemname', 'ENQ_JNY_DAY_POI.LF.M');
        u0.AddParameter('ENQ_JNY_DAY_ID', "@ENQ_JNY_DAY_ID");
        $Install(u0, getObj('#poi'), ()=>{});

        ewa._init_des = createDescription();
        loadActionJson_addrs();

        getObj('#EJD_TIME_BUCKET').on('change', function() {
            let opt = $(this).find('option:selected');
            if (!opt.attr('json')) {
                return;
            }
            const json = JSON.parse(opt.attr('json'));
            if (json.BAS_TAG_PARA1) {
                getObj('#EJD_TIME_BEGIN').val(json.BAS_TAG_PARA1);
            }
            if (json.BAS_TAG_PARA2) {
                getObj('#EJD_TIME_END').val(json.BAS_TAG_PARA2);
            }
        });
        getObj('#EJD_TIME_BEGIN,#EJD_TIME_END').on('blur', function() {
            this.value = enqJnyDesign.normalizeTimeWithSuffix(this.value);
        });
        getObj('input,select,textarea').on('change', () => {
            change();
        });
        if ("@K0_ADDR") {
            getObj('#EDJ_PLACE_END').val("@K0_ADDR");
            change();
        }
        const ai0 = $(' <a>AI查</a>');
        ai0.on('click', function() {
            aiDistance();
        });
        getObj('.ewa-row-EJD_TRANSPORT_DISTANCE .EWA_TD_L').append(ai0)
        const airline = $(' <a>航班查询</a>');
        airline.on('click', function() {
            airlinesSearch();
        });
        getObj('.ewa-row-EDJ_AIRLINES .EWA_TD_L').append(airline)
    }
    init();
})();

