SELECT A.* FROM ENQ_JNY_DAY A WHERE REF_TABLE = 'CUSTOM-TIME-SCHEDULE' -- ewa_test @enq_jny_ser_sub_id > 0 AND REF_ID = @enq_jny_ser_sub_id -- ewa_test @enq_jny_ser_sub_id = 0 AND GRP_ID = @GRP_ID AND EJD_TMP_RID = @EJD_TMP_RID -- ewa_test AND sup_id = @G_SUP_ID;
-- ewa_test @ENQ_JNY_DAY_ID is null INSERT INTO ENQ_JNY_DAY ( GRP_ID, ENQ_JNY_ID, ENQ_JNY_DAY, ENQ_JNY_DATE, CREATE_TIME, ADM_ID, SUP_ID, EJD_CITY_ID, REF_TABLE, SER_KEY0, SER_KEY1, SER_KEY2, EJD_STATUS, REF_ID, EJD_TMP_RID, ser_id ) VALUES ( @GRP_ID, @ENQ_JNY_ID, @ENQ_JNY_DAY, @ENQ_JNY_DATE, @SYS_DATE, @G_ADM_ID, @G_SUP_ID, @CITY_ID, 'CUSTOM-TIME-SCHEDULE', @SER_KEY0, @SER_KEY1, -1, 'new', @enq_jny_ser_sub_id, @EJD_TMP_RID, @ser_id ) -- auto ENQ_JNY_DAY_ID -- ewa_test @ENQ_JNY_DAY_ID is not null
SELECT a.*, sm0.SUP_ADDR K0_ADDR, sm0.SUP_NAME K0_SUP_NAME FROM V_SER_CONN_DETAIL a LEFT JOIN sup_main sm0 ON a.k0_ref_id = sm0.SUP_ID AND a.K0_REF_BASE = 'SUP_MAIN' WHERE a.city_id = @city_id AND a.ser_id = @ser_id AND a.ser_key0 = @ser_key0 AND a.ser_key1 = @ser_key1 AND a.PURCHASER_SUP_ID = @G_SUP_ID

