}
function showPoiInfo(piUnid) {
    let width = document.documentElement.clientWidth;
    let height = document.documentElement.clientHeight;
    if (width > 700) {
        width -= 100 ;
    } 
    if (height > 400) {
        height = height - 100;
    }
    const u = "@ewa.cp/ewa?xmlname=/front-web/poi/poi.xml&ITEMNAME=POI_INFO.F.V&pi_unid=" +
        piUnid + "";
    top.$DialogInstall(u, null, width, height, true);
}
(function() {
    let ewa = EWA.F.FOS['@SYS_FRAME_UNID'];
    ewa.ReloadAfter = function(httpReferer) {
        if("@IS_READONLY"==""){
            getObj().parent().addClass('ewa-break');
            getObj().parent().append(`<input type='button' class="IX_BUTTON" value='添加' onclick="EWA.F.FOS['@sys_frame_unid'].ext_AddNew()">`);
        }
    };

    ewa.ext_AddNew = function() {
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.RemoveEwa();
        u1.AddParameter("EWA_MTYPE", "N");
        u1.AddParameter("callback", "setPoiId");
        let paras = u1.GetParas();
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '/meta-data/poi/poi_info.xml', 'POI_INFO.F.N_GOOGLE', false, paras);
    };
    ewa.ext_AddNew1111 = function() {
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.RemoveEwa();
        u1.AddParameter("EWA_MTYPE", "N");
        let paras = u1.GetParas();
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '@xmlName', 'ENQ_JNY_DAY_POI.F.NM', false, paras);
    };

    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }

    // 执行刷新后事件
    function init() {
        ewa.ReloadAfter();
    }
    init();
})();

