(function() {
    let ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    const basTags = $J2MAP1(JSON.parse("@EWA.FRAME.DATA.BAS_TAGS"), "BAS_TAG");

    const ptr = getObj().parent().parent().prev();
    ewa.DoPostBefore = function() {
        ewa.PostAddData = {
            "ENQ_JNY_DAY_ID": "@ENQ_JNY_DAY_ID"
        }
        return true;
    };
    if (window.timeListRefresh) {
        ewa.doPostAfter = function() { //修改时刷新左边列表
            $Tip('修改完毕')
            window.timeListRefresh();
        };
    }

    if ("@parent_frame_unid") {
        ewa.doPostAfter = function() { //修改时刷新左边列表
            $Tip('修改完毕');
            const search = "ENQ_JNY_DAY_ID=@ENQ_JNY_DAY_ID";
            EWA.F.FOS["@parent_frame_unid"].replaceRowsData(search, null, null, null, true);
        };
    }

    function getObj(exp) {
        return exp ? $('#f_@sys_frame_unid').find(exp) : $('#f_@sys_frame_unid');
    }

    function normalizeTimeWithSuffix(input) {
        // 确保输入为字符串
        const str = String(input);
        const [time, suffix = ''] = str.split('+');

        // 替换非标准分隔符为冒号并移除非数字和冒号字符
        const cleaned = time
            .replace(/[：∶．·\-_]/g, ':') // 替换中文/全角冒号、点号、横线等
            .replace(/[^0-9:]/g, ''); // 保留数字和冒号

        // 如果包含冒号，直接处理
        if (cleaned.includes(':')) {
            let [hour, minute] = cleaned.split(':');
            hour = hour.padStart(2, '0'); // 补齐两位小时
            minute = minute.padStart(2, '0'); // 补齐两位分钟
            return `${hour}:${minute}${suffix ? '+' + suffix : ''}`;
        }

        // 处理纯数字情况
        const num = cleaned.replace(/\D/g, ''); // 移除所有非数字字符
        const len = num.length;

        if (len === 1) return `0${num}:00${suffix ? '+' + suffix : ''}`;
        if (len === 2) return `${num}:00${suffix ? '+' + suffix : ''}`;
        if (len === 3) return `${num[0]}:0${num.slice(1)}${suffix ? '+' + suffix : ''}`;
        if (len === 4) return `${num.slice(0, 2)}:${num.slice(2)}${suffix ? '+' + suffix : ''}`;

        return input; // 无效输入返回原值
    }


    function loadActionJson_addrs() {
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);

        u1.AddParameter("ewa_action", "SAct0");
        u1.AddParameter("ewa_ajax", "json");

        let u = u1.GetUrl();

        $J(u, function(rst) {
            const ss = ['<datalist id="addrs" >'];
            for (let n in rst) {
                let d = rst[n]; //数据行
                let s = `<option value="${d.addr}"></option>`;
                ss.push(s)
            }
            ss.push('</datalist>');
            getObj().append(ss.join(''));

            getObj('#EDJ_PLACE_BEGIN,#EDJ_PLACE_END').attr('list', 'addrs');
        });

    }

    function change() {
        // 
    }

    function aiDistance() {
        const prompt = getObj('#EDJ_PLACE_BEGIN').val() + " 到 " + getObj('#EDJ_PLACE_END').val();
        const u = "@ewa.cp/back_admin/ai/stream.jsp?MODE=getdistance" +
            "&request_id=" + crypto.randomUUID() +
            "&mode=getdistance&prompt=&ai_model=qwen-plus&ai_provider=qwen&ai_thinking=false" +
            "&prompt=" + prompt.toURL();
        $J(u, function(rst) {
            if (!rst.RST) {
                alert(rst.ERR);
                return;
            }
            let content = rst.content;
            if (content.indexOf('```json') >= 0) {
                content = content.split('```json')[1];
                content = content.split('```')[0];
            }
            const json = JSON.parse(content);
            getObj('#EJD_TRANSPORT_DISTANCE').val(json.distance);
            getObj('#EJD_TIME_SPAN').val(json.time);

            //console.log(rst);
            change();
        });
    }


    function init() {
        const u0 = new EWA_UrlClass(ewa.Url);
        u0.AddParameter('itemname', 'ENQ_JNY_DAY_POI.LF.M');
        u0.AddParameter('ENQ_JNY_DAY_ID', "@ENQ_JNY_DAY_ID");
        $Install(u0, getObj('#poi'), () => {});

        loadActionJson_addrs();

        getObj('#EJD_TYPE').on('change', function() {
            let opt = $(this).find('option:selected');
            console.log(opt);
            if (!opt.attr('json')) {
                return;
            }
            const json = JSON.parse(opt.attr('json'));
            if (json.BAS_TAG_PARA1) {
                getObj('#EJD_TIME_BEGIN').val(json.BAS_TAG_PARA1);
            }
            if (json.BAS_TAG_PARA2) {
                getObj('#EJD_TIME_END').val(json.BAS_TAG_PARA2);
            }
        });
        getObj('#EJD_TIME_BEGIN,#EJD_TIME_END').on('blur', function() {
            this.value = normalizeTimeWithSuffix(this.value);
        });
        getObj('input,select,textarea').on('change', () => {
            change();
        });

        if ("@K0_ADDR") {
            getObj('#EDJ_PLACE_END').val("@K0_ADDR");
            change();
        }
        const ai0 = $(' <a>AI查</a>');
        ai0.on('click', function() {
            aiDistance();
        });
        getObj('.ewa-row-EJD_TRANSPORT_DISTANCE .EWA_TD_L').append(ai0)

        // const airline = $(' <a>航班查询</a>');
        // airline.on('click', function() {
        //     airlinesSearch();
        // });
        // getObj('.ewa-row-EDJ_AIRLINES .EWA_TD_L').append(airline);


        getObj("#EJD_SER_TAG_DES").on("change", function() {
            let v = $(this).val();

            let basTagPara1 = "";
            if (v) {
                basTagPara1 = basTags[v][0]["BAS_TAG_PARA1"];
            }

            if (basTagPara1 == "SER_TAG_CAR") {
                getObj(".ewa-row-EDJ_AIRLINES").show();
                getObj(".ewa-row-VEHICLE_PLATE_NO").show();
                getObj(".ewa-row-DESTINATION_TYPE").show();
            } else {
                getObj(".ewa-row-DESTINATION_TYPE").hide();
                getObj(".ewa-row-VEHICLE_PLATE_NO").hide();
                getObj(".ewa-row-EDJ_AIRLINES").hide();
                getObj("#EDJ_AIRLINES").val("");
                getObj("#VEHICLE_PLATE_NO").val("");
                getObj("#DESTINATION_TYPE").val("");
            }

            if (basTagPara1 == "SER_TAG_GUIDE") {
                getObj(".ewa-row-GUIDES").show();
            } else {
                getObj(".ewa-row-GUIDES").hide();
                getObj("#GUIDES").val("");
            }
        }).change();
    }
    init();
})();

