Set.Sql:
-- ewa_sql_split_no SELECT top 1 'Y' IS_READONLY FROM ENQ_MAIN em INNER JOIN ENQ_JNY ej ON ej.ENQ_ID = em.ENQ_ID INNER JOIN GRP_MAIN gm ON em.GRP_ID = gm.GRP_ID WHERE (em.FLOW_STATE IN ('ENQ_END', 'ENQ_CONTRACT_VALID','ENQ_CUS_YES') or gm.GRP_STA='SCM_GRP_STA_UNENQ') -- ewa_test @ENQ_JNY_DAY_ID is null and ej.ENQ_JNY_ID=@ENQ_JNY_ID -- ewa_test @ENQ_JNY_DAY_ID is not null and ej.ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY_DAY where ENQ_JNY_DAY_ID = @ENQ_JNY_DAY_ID) -- ewa_test -- AND gm.GRP_RUN_MODEL = 'GRP_RUN_SINGLE' -- 散拼可以改，要改航班和日期，2025-01-22，吕国芳 ;
-- ewa_test @EWA_MTYPE='M' SELECT A.* FROM ENQ_JNY_DAY A WHERE REF_TABLE = 'CUSTOM-TIME-SCHEDULE' AND ENQ_JNY_DAY_ID = @ENQ_JNY_DAY_ID AND sup_id = @G_SUP_ID -- ewa_test ;
-- ewa_table_name BAS_TAGS SELECT a.BAS_TAG, a.BAS_TAG_NAME, a.BAS_TAG_PARA1 FROM BAS_TAG a WHERE a.BAS_TAG_GRP = 'SER_DES' ORDER BY a.BAS_TAG_ORD

SELECT
   top 1 case when gm.GRP_STA='SCM_GRP_STA_UNENQ' then '已成团不能修改' 
        else '审批流程已到等待客户确认，不能修改' end EWA_ERR_OUT
FROM
    ENQ_MAIN em
    INNER JOIN ENQ_JNY ej ON ej.ENQ_ID = em.ENQ_ID
    INNER JOIN GRP_MAIN gm ON em.GRP_ID = gm.GRP_ID
WHERE (em.FLOW_STATE IN ('ENQ_END', 'ENQ_CONTRACT_VALID','ENQ_CUS_YES') or gm.GRP_STA='SCM_GRP_STA_UNENQ')
    and ej.ENQ_JNY_ID = @ENQ_JNY_ID
    -- AND gm.GRP_RUN_MODEL = 'GRP_RUN_SINGLE' -- 散拼可以改，要改航班和日期，2025-01-22，吕国芳
;

