SELECT top 1 case when gm.GRP_STA='SCM_GRP_STA_UNENQ' then '已成团不能修改' else '审批流程已到等待客户确认，不能修改' end EWA_ERR_OUT FROM ENQ_MAIN em INNER JOIN ENQ_JNY ej ON ej.ENQ_ID = em.ENQ_ID INNER JOIN GRP_MAIN gm ON em.GRP_ID = gm.GRP_ID WHERE (em.FLOW_STATE IN ('ENQ_END', 'ENQ_CONTRACT_VALID','ENQ_CUS_YES') or gm.GRP_STA='SCM_GRP_STA_UNENQ') and ej.ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY_DAY where ENQ_JNY_DAY_ID = @ENQ_JNY_DAY_ID) -- AND gm.GRP_RUN_MODEL = 'GRP_RUN_SINGLE' -- 散拼可以改，要改航班和日期，2025-01-22，吕国芳 ;
UPDATE ENQ_JNY_DAY SET EJD_TYPE = @EJD_TYPE, EJD_TIME_BEGIN = @EJD_TIME_BEGIN, EJD_TIME_END = @EJD_TIME_END, EDJ_PLACE_BEGIN = @EDJ_PLACE_BEGIN, EDJ_PLACE_END = @EDJ_PLACE_END, EDJ_REMARK = @EDJ_REMARK, ADM_ID = @G_ADM_ID, EJD_CITY_ID = @CITY_ID, SER_KEY0 = @SER_KEY0, SER_KEY1 = @SER_KEY1, SER_KEY2 = @SER_KEY2, GUIDES = @GUIDES, EJD_MDATE = @SYS_DATE, EDJ_PLACE_BEGIN_EN = @EDJ_PLACE_BEGIN_EN, EDJ_PLACE_END_EN = @EDJ_PLACE_END_EN, GUIDES_EN = @GUIDES_EN, EDJ_REMARK_EN = @EDJ_REMARK_EN, EJD_TIME_SPAN = @EJD_TIME_SPAN, EJD_TRANSPORT_DISTANCE = @EJD_TRANSPORT_DISTANCE, EDJ_DESC = @EDJ_DESC, EDJ_DESC_EN = @EDJ_DESC_EN, EDJ_AIRLINES = @EDJ_AIRLINES, EJD_SER_TAG_DES = @EJD_SER_TAG_DES, EJD_STATUS = 'USED', DESTINATION_TYPE = @DESTINATION_TYPE, VEHICLE_PLATE_NO = @VEHICLE_PLATE_NO
WHERE ENQ_JNY_DAY_ID = @ENQ_JNY_DAY_ID AND SUP_ID = @G_SUP_ID

Set.Bottom:
function show_enq_jny_ser_subs() {
    var tb = $('#EWA_FRAME_@sys_frame_unid');
    var refEnqJnyId = tb.find("#ENQ_JNY_ID_FROM").val();

    if(!refEnqJnyId){
        return;
    }

    var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
    u1.AddParameter("itemname", "ENQ_JNY_SER_SUB.Lf.CopyRef");
    u1.AddParameter("REF_ENQ_JNY_ID", refEnqJnyId);
    var u = u1.GetUrl();
    var target = tb.find("#services div");
    $Install(u, target, function() {
        var refSelect = tb.find("#ENQ_JNY_ID_FROM")[0];
        tb.attr('selectall', 1);
        var opt = refSelect.options[refSelect.selectedIndex];
        var json = JSON.parse(opt.getAttribute('json'));
        var map = {};
        map[json.F_ADD] = true;
        if (json.TO_ADD) {
            map[json.TO_ADD] = true;
        }
        if (json.TO_ADD2) {
            map[json.TO_ADD2] = true;
        }
        if (json.CITY_ID) {
            map[json.CITY_ID] = true;
        }

        tb.find(".ewa-row-ENQ_JNY_IDS input").each(function() {
            this.checked = false;
            if (refEnqJnyId == this.value) {
                $(this).prop("disabled", true);
                return;
            }
            var json1 = JSON.parse(this.getAttribute('json'));
            if (map[json1.F_ADD] || map[json1.TO_ADD] || map[json1.TO_ADD2] || map[json1.CITY_ID]) {
                $(this).prop("disabled", false);
            } else {
                $(this).prop("disabled", true);
            }
        });
        EWA.F.FOS["@SYS_FRAME_UNID"].ext_select_default_jny();
    });
}
(function() {
    let ewa=EWA.F.FOS["@sys_frame_unid"];
    var tb = $('#EWA_FRAME_@sys_frame_unid');

    ewa.ext_enq_jny_ids="@ENQ_JNY_IDS".split(",");

    ewa.ext_select_default_jny=function(){
        for(let i=0;i<ewa.ext_enq_jny_ids.length;i++){
            let ipt=tb.find(".ewa-row-ENQ_JNY_IDS input[value='"+ewa.ext_enq_jny_ids[i]+"']");
            if(!ipt.prop("disabled")){
                ipt.prop("checked",true);
            }
        }
    }
    ewa.ext_all=function(){
        var refSelect = tb.find("#ENQ_JNY_ID_FROM")[0];
        if (refSelect.selectedIndex <= 0) {
            $Tip("请先选择参考");
            return;
        }
        var isSelectAll = tb.attr('selectall') == "1";
        if (isSelectAll) {
            tb.attr('selectall', 0);
        } else {
            tb.attr('selectall', 1);
        }
        tb.find(".ewa-row-ENQ_JNY_IDS input").each(function() {
            if (!this.disabled) {
                this.checked = isSelectAll;
            } else {
                this.checked = false;
            }
        });
    }
    var a = $("<a style='margin-left: 5px' onclick=\"EWA.F.FOS['@sys_frame_unid'].ext_all()\">全选</a>");

    tb.find('.ewa-row-ENQ_JNY_IDS .EWA_TD_L').append(a).css('white-space', 'nowrap');

    show_enq_jny_ser_subs();
})();
/**
 * Frame 提交前进行检查，返回true，则可以提交数据
 * 同时可以手动增加提交的参数
 **/
EWA.F.FOS["@sys_frame_unid"].DoPostBefore = function() {
    var tb = $('#EWA_FRAME_@sys_frame_unid');
    var ser_ids = [],
        ser_city_ids = [],
        enq_jny_ser_sub_ids = [];
    tb.find(".ewa-col-ENQ_JNY_SER_SUB_ID input:checked").each(function() {
        var ser_id = $(this).attr('ser_id');
        var ser_city_id = $(this).attr('ser_city_id');
        var enq_jny_ser_sub_id = this.value;
        ser_ids.push(ser_id);
        ser_city_ids.push(ser_city_id);
        enq_jny_ser_sub_ids.push(enq_jny_ser_sub_id);
    });
    if (ser_ids.length === 0) {
        $Tip('请选择要复制到的日期');
        return false;
    }

    var add_data = {};
    // add_data["ser_ids"] = ser_ids.join(',');
    // add_data["ser_city_ids"] = ser_city_ids.join(',');
    add_data["enq_jny_ser_sub_ids"] = enq_jny_ser_sub_ids.join(',');

    var postData = this.CreatePostData();
    // 要复制到的日期
    add_data["enq_jny_ids"] = postData.ENQ_JNY_IDS; 

    this.PostAddData = add_data;


    return true;
}

