Set.Sql:
SELECT
    case when gm.GRP_STA='SCM_GRP_STA_UNENQ' then '已成团不能修改' 
        else '审批流程已到等待客户确认，不能修改' end EWA_ERR_OUT
FROM
    ENQ_MAIN em
    INNER JOIN GRP_MAIN gm ON em.GRP_ID = gm.GRP_ID
WHERE
    em.ENQ_ID = @ENQ_ID
    AND (em.FLOW_STATE IN ('ENQ_END', 'ENQ_CONTRACT_VALID','ENQ_CUS_YES') or gm.GRP_STA='SCM_GRP_STA_UNENQ')
    -- AND gm.GRP_RUN_MODEL = 'GRP_RUN_SINGLE' -- 散拼可以改，要改航班和日期，2025-01-22，吕国芳
;

EXEC PR_COPY_ENQ_SERVICES @ENQ_ID,
@enq_jny_ids,
@enq_jny_ser_sub_ids,
@g_sup_id,
@g_adm_id

Set.Bottom:
(function() {
    let ewa = EWA.F.FOS["@sys_frame_unid"];

    EWA.F.FOS["@sys_frame_unid"].batModify = function() {
        let ids = [];
        let id = -1;
        var tb = $('#EWA_LF_@sys_frame_unid');
        $("#EWA_LF_@sys_frame_unid>tbody>tr>td>input[name='ENQ_JNY_ID']:checked").each(function() {
            ids.push($(this).val());
        });
        let paras = "ENQ_ID=@ENQ_ID&ENQ_JNY_ID_FROM=" + ids[0];
        if (ids.length > 0) {
            paras += "&ENQ_JNY_IDS=" + ids.join(",");
        }
        EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid", "/business/enq/enqJnyDesign.xml", "ENQ_JNY.F.batModify", false, paras);
    }

    EWA.F.FOS["@sys_frame_unid"].batDelete = function() {
        let ids = [];
        $("#EWA_LF_@sys_frame_unid>tbody>tr.ewa-lf-data-row").each(function() {
            if ($(this).find("input[name='ENQ_JNY_ID']:checked").length > 0) {
                ids.push($(this).attr("ewa_key"));
            }
        });
        if (ids.length == 0) {
            return;
        }
        var paras = [];
        paras[0] = {
            Name: 'IDS_SPLIT',
            Value: ids.join(",")
        };
        EWA.F.FOS["@sys_frame_unid"].DoAction(this, "batDelJny", "确认删除吗?", "", paras);
    }
    // ewa.ReloadAfter(1);
    ewa.ReloadAfter = function() {
        if("@EWA_PARENT_FRAME"){
            EWA.OW.Load();
            EWA.OW.PWin.EWA.F.FOS["@EWA_PARENT_FRAME"].Reload();
        }
    }
})();

Set.Sql:
DELETE FROM ENQ_JNY WHERE ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

delete from ENQ_JNY_SER where ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

delete from ENQ_JNY_SER_SUB where ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

exec PR_ENQ_FEE @enq_id;

exec PR_ENQ_TO_PRICE @ENQ_ID;

UPDATE  ENQ_JNY SET ENQ_JNY_FORM_ID = -1 -- 借用， 0表示删除
    WHERE ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID
;

SELECT top 1 case when gm.GRP_STA='SCM_GRP_STA_UNENQ' then '已成团不能修改' else '审批流程已到等待客户确认，不能修改' end EWA_ERR_OUT FROM ENQ_MAIN em INNER JOIN ENQ_JNY ej ON ej.ENQ_ID = em.ENQ_ID INNER JOIN GRP_MAIN gm ON em.GRP_ID = gm.GRP_ID WHERE ej.ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY where ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id) AND (em.FLOW_STATE IN ('ENQ_END', 'ENQ_CONTRACT_VALID','ENQ_CUS_YES') or gm.GRP_STA='SCM_GRP_STA_UNENQ') -- AND gm.GRP_RUN_MODEL = 'GRP_RUN_SINGLE' -- 散拼可以改，要改航班和日期，2025-01-22，吕国芳 ;
delete from ENQ_JNY_SER where ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY where ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id) AND SUP_ID=@G_SUP_ID;
delete from ENQ_JNY_SER_SUB where ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY where ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id) AND SUP_ID=@G_SUP_ID;
DELETE FROM ENQ_JNY WHERE ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id AND SUP_ID=@G_SUP_ID;
exec PR_ENQ_FEE @enq_id;
exec PR_ENQ_TO_PRICE @ENQ_ID;
select 1 DEL_OK;

SELECT em.SUP_ID, a.SER_ID, a.SER_CONN_ID, ejss.ENQ_JNY_ID, ejss.ENQ_JNY_SER_SUB_TMP_RID , c.PI_UNID, c.PI_NAME, c.PI_SUMMARY, c.PI_RATING FROM enq_main em INNER JOIN ENQ_JNY_SER_SUB ejss ON em.ENQ_ID = ejss.FRO_ENQ_ID AND em.SUP_ID = ejss.SUP_ID INNER JOIN SER_CONN a ON ejss.SER_CONN_ID = a.SER_CONN_ID INNER JOIN ser_key b ON a.SER_KEY0 = b.ser_key_id INNER JOIN ser_tag st ON b.TAG0 = st.SER_TAG_ID AND st.SER_TAG_REF_TABLE = 'POI_INFO' INNER JOIN POI_INFO c ON st.SER_TAG_REF_ID = c.pi_ID AND c.PI_STATUS = 'USED' WHERE em.ENQ_ID = @ENQ_ID ; SELECT ejss.ENQ_JNY_ID, ejss.ENQ_JNY_SER_SUB_TMP_RID , c.PI_UNID, d.PP_UNID FROM enq_main em INNER JOIN ENQ_JNY_SER_SUB ejss ON em.ENQ_ID = ejss.FRO_ENQ_ID AND em.SUP_ID = ejss.SUP_ID INNER JOIN SER_CONN a ON ejss.SER_CONN_ID = a.SER_CONN_ID INNER JOIN ser_key b ON a.SER_KEY0 = b.ser_key_id INNER JOIN ser_tag st ON b.TAG0 = st.SER_TAG_ID AND st.SER_TAG_REF_TABLE = 'POI_INFO' INNER JOIN POI_INFO c ON st.SER_TAG_REF_ID = c.pi_ID AND c.PI_STATUS = 'USED' INNER JOIN POI_PIC d ON c.pi_ID = d.pi_ID AND PP_STATUS = 'USED' WHERE em.ENQ_ID = @ENQ_ID ORDER BY PP_IS_PRIMARY DESC, PP_ORDER;
SELECT c.ENQ_JNY_DAY_ID, d.PI_UNID, d.PI_NAME, d.PI_SUMMARY, d.PI_RATING FROM ENQ_JNY_DAY a INNER JOIN enq_jny b ON a.enq_jny_id = b.enq_jny_id AND b.ENQ_ID = @ENQ_ID INNER JOIN ENQ_JNY_DAY_POI c ON a.ENQ_JNY_DAY_ID = c.ENQ_JNY_DAY_ID INNER JOIN poi_info d ON c.PI_ID = d.PI_ID AND d.PI_STATUS = 'USED';
SELECT c.ENQ_JNY_DAY_ID, e.PP_UNID, d.PI_UNID FROM ENQ_JNY_DAY a INNER JOIN enq_jny b ON a.enq_jny_id = b.enq_jny_id AND b.ENQ_ID = @ENQ_ID INNER JOIN ENQ_JNY_DAY_POI c ON a.ENQ_JNY_DAY_ID = c.ENQ_JNY_DAY_ID INNER JOIN poi_info d ON c.PI_ID = d.PI_ID AND d.PI_STATUS = 'USED' INNER JOIN poi_pic E ON d.PI_ID = e.PI_ID AND E.PP_STATUS = 'USED'

