Set.Sql:
SELECT enq_car_id AS car_id, enq_hotel_id AS hotel_id, head_num, people_num, head_num + people_num AS nums FROM enq_main WHERE enq_id = @enq_id;
SELECT TOP 1 city_id f_add, ENQ_JNY_DAY + 1 ENQ_JNY_DAY, ENQ_JNY_DATE + 1 ENQ_JNY_DATE FROM enq_jny WHERE enq_id = @enq_id ORDER BY ENQ_JNY_DAY DESC;
-- ewa_test @ENQ_JNY_DAY is null SELECT 1 AS ENQ_JNY_DAY, f_city AS f_add, f_date AS ENQ_JNY_DATE FROM enq_main WHERE enq_id = @enq_id -- ewa_test ;
-- 关联营地的成本团 2024-09-24 SELECT camp_id AS cost_camp_id, CO_STUDENT, CO_CS, CO_CS_MEDIA, CO_CS_MEDICAL, CO_FOREIGN_TEACHER, CO_CHINES_TEACHAR FROM camp_open co WHERE co.co_cost_grp_id = @grp_id;
-- 营地关联的 ser_key0 SELECT ser_key_id AS camp0_key_id FROM ser_key WHERE SER_KEY_REF_BASE = 'CAMP_MAIN' AND REF_ID = @cost_camp_id AND SER_KEY_STATUS = 'USED' AND SER_ID = 11 AND ser_key_grp = 'CAMP0';
-- ewa_table_name sys_coin SELECT COIN_ID, COIN_NAME, COIN_KEY FROM sys_coin;

insert into _ewa_spt_data (idx, col, tag) select ser_conn_id, 'enq_jny.f.nm', @sys_unid from ( select ser_conn_id from ENQ_JNY_SER_SUB where enq_jny_id=@enq_jny_id and SER_CITY_ID = @CITY_ID UNION SELECT A.SER_CONN_ID FROM SER_CONN A WHERE ( A.OWN_SUP_ID=@G_SUP_ID and SER_CONN_STATE='USED' and ( CITY_ID=@CITY_ID OR CITY_ID IN (SELECT COUNTRY_ID FROM CITY WHERE CITY_ID=@CITY_ID) ) and SER_CONN_EDATE >= getdate() and ser_conn_ver = '2026' and A.SER_CONN_PROVIDER_SUP_ID > 0 ) UNION SELECT A.SER_CONN_ID FROM SER_CONN A WHERE ( (A.SUP_ID=@G_SUP_ID and OWN_SUP_ID in (select SUP_ID from enq_jny where enq_jny_id=@enq_jny_id)) and SER_CONN_STATE='USED' and ( CITY_ID=@CITY_ID OR CITY_ID IN (SELECT COUNTRY_ID FROM CITY WHERE CITY_ID=@CITY_ID) ) and SER_CONN_EDATE >= getdate() and ser_conn_ver = '2026' and A.SER_CONN_PROVIDER_SUP_ID > 0 )
) a; -- ewa_table_name ser_main SELECT SER_ID,SER_PID,SER_NAME,SER_SCALE,SER_TAG FROM SER_MAIN WHERE SUP_ID=3 and ser_ob3 = 'USED' -- 服务大类描述 ; -- ewa_table_name ser_conn SELECT A.SER_ID , A.SER_CONN_ID , DBO.F_SER_DEP_LVL(@GRP_ID,SER_CONN_ID) AS SER_PRICE , A.COIN_ID , A.SUP_ID , a.SER_CONN_PROVIDER_SUP_ID , A.SER_KEY0 , A.SER_KEY1 , A.SER_KEY2 , A.CITY_ID , A.SER_CONN_EDATE , key1.SER_KEY_ORD as SER_KEY1_ORD , A.SER_CONN_CAT_ID , sc.SER_CAT_NAME , sc.SER_CAT_NAME_EN FROM SER_CONN A left join ser_key key1 on a.SER_KEY1 = key1.SER_KEY_ID left join ser_cat sc on a.SER_CONN_CAT_ID = sc.SER_CAT_ID inner join _ewa_spt_data b on a.SER_CONN_ID = b.IDx and b.tag=@sys_unid order by SER_KEY_ORD -- 城市下的所有服务 ;
-- ewa_table_name ser_key SELECT SER_ID , SER_KEY_ID , ISNULL(SER_KEY_GRP,'') SER_KEY_GRP , SER_KEY_NAME , SER_KEY_REMARK , SER_KEY_DEF , SER_KEY_EX3 , bt.BAS_TAG_PARA1 , bt.BAS_TAG_PARA2 , bt.BAS_TAG_PARA3 , bt.BAS_TAG_PARA4 , bt.BAS_TAG_PARA5 , bt.BAS_TAG_PARA6 FROM SER_KEY a LEFT join bas_tag bt on a.SER_KEY_EX3 = bt.bas_tag WHERE SER_KEY_STATUS = 'USED' AND (SER_KEY_ID IN ( SELECT SER_KEY0 FROM SER_CONN A inner join _ewa_spt_data b on a.SER_CONN_ID = b.IDx and b.tag=@sys_unid UNION all SELECT SER_KEY1 FROM SER_CONN A inner join _ewa_spt_data b on a.SER_CONN_ID = b.IDx and b.tag=@sys_unid UNION all select distinct ser_key0 from ENQ_JNY_SER_SUB WHERE enq_jny_id=@enq_jny_id UNION all select distinct ser_key1 from ENQ_JNY_SER_SUB WHERE enq_jny_id=@enq_jny_id ) ) ORDER BY SER_KEY_GRP,SER_KEY_NAME ;
-- 服务下的供应商/服务商信息 -- ewa_table_name sup_main SELECT B.SUP_NAME,B.SUP_ID FROM SUP_MAIN B inner join ( SELECT distinct SUP_ID FROM SER_CONN A -- 供应商 inner join _ewa_spt_data b on a.SER_CONN_ID = b.IDx and b.tag=@sys_unid UNION SELECT distinct SER_CONN_PROVIDER_SUP_ID FROM SER_CONN A -- 服务商 inner join _ewa_spt_data b on a.SER_CONN_ID = b.IDx and b.tag=@sys_unid ) A on b.SUP_ID = a.SUP_ID ; -- ewa_table_name ser_key_logic select SER_KEY_ID,SER_LGC_NUM0,SER_LGC_NUM1,SER_LGC_DY FROM SER_KEY_LOGIC WHERE SUP_ID=@G_SUP_ID AND SER_LGC_NUM0>=@NUMS;
-- 已经保存的预算数据 -- ewa_table_name enq_jny_ser_sub select A.SER_ID , A.ENQ_JNY_SER_SUB_ID , A.ser_conn_id , B.SUP_ID AS sup_id , A.sup_down_id , a.sub_num , b.SER_KEY0 , b.SER_KEY1 , b.SER_KEY2 , b.CITY_ID , c.COUNTRY_ID , a.enq_jny_price , a.ENQ_JNY_SER_REMARK , t.EJD_TIME_BEGIN , t.EDJ_REMARK , t.EDJ_PLACE_BEGIN , t.GUIDES , t.EDJ_REMARK_EN , t.EDJ_PLACE_BEGIN_EN , t.GUIDES_EN from ENQ_JNY_SER_SUB A LEFT JOIN SER_CONN B ON A.SER_CONN_ID=B.SER_CONN_ID LEFT join city C on b.CITY_ID = c.CITY_ID LEFT join ADM_USER_GRP_SUB dj on a.SUP_ID = dj.SUP_ID and dj.SUB_ADM_ID = @g_adm_id and dj.SUB_SUP_ID = @g_sup_id left join ENQ_JNY_DAY t on a.SER_CONN_ID = t.ref_id and t.ref_table = 'ENQ_JNY_SER_SUB' where a.enq_jny_id=@enq_jny_id and (A.sup_id=@g_sup_id or dj.sup_id >0) order by ENQ_JNY_SER_SUB_ID desc ;
-- ewa_table_name sys_coin SELECT COIN_ID,COIN_NAME,COIN_KEY FROM SYS_COIN -- 货币信息 ;
-- ewa_table_name enq_jny_day select * from ENQ_JNY_DAY e where ENQ_JNY_ID = @enq_jny_id
delete from _ewa_spt_data where tag = @sys_unid

----- 供应商用，需要enq_op_id ----- SELECT SER_ID, SER_NAME, SER_SCALE, SER_TAG FROM SER_MAIN WHERE SUP_ID = 3 -- 服务大类描述 ;
SELECT A.SER_ID, A.SER_CONN_ID, DBO.F_SER_DEP_LVL (@GRP_ID, SER_CONN_ID) AS SER_PRICE, A.COIN_ID, A.SUP_ID, A.SER_KEY0, A.SER_KEY1, A.SER_KEY2, A.CITY_ID, A.SER_CONN_EDATE, key1.SER_KEY_ORD AS SER_KEY1_ORD, A.SER_CONN_CAT_ID, sc.SER_CAT_NAME, sc.SER_CAT_NAME_EN FROM SER_CONN A LEFT JOIN ser_key key1 ON a.SER_KEY1 = key1.SER_KEY_ID LEFT JOIN ser_cat sc ON a.SER_CONN_CAT_ID = sc.SER_CAT_ID INNER JOIN ENQ_JNY_CACHE_CITYS b ON a.CITY_ID = b.CITY_ID AND b.enq_jny_id = @enq_jny_id AND a.OWN_SUP_ID = @G_SUP_ID WHERE a.CITY_ID = @CITY_ID ORDER BY SER_KEY_ORD -- 城市下的所有服务 ;
WITH ser_keys AS ( SELECT DISTINCT A.SER_KEY0 AS id FROM SER_CONN A INNER JOIN ENQ_JNY_CACHE_CITYS b ON a.CITY_ID = b.CITY_ID AND b.enq_jny_id = @enq_jny_id AND a.OWN_SUP_ID = @G_SUP_ID UNION SELECT DISTINCT A.SER_KEY1 FROM SER_CONN A INNER JOIN ENQ_JNY_CACHE_CITYS b ON a.CITY_ID = b.CITY_ID AND b.enq_jny_id = @enq_jny_id AND a.OWN_SUP_ID = @G_SUP_ID UNION SELECT DISTINCT A.SER_KEY2 FROM SER_CONN A INNER JOIN ENQ_JNY_CACHE_CITYS b ON a.CITY_ID = b.CITY_ID AND b.enq_jny_id = @enq_jny_id AND a.OWN_SUP_ID = @G_SUP_ID ) SELECT SER_ID, SER_KEY_ID, ISNULL(SER_KEY_GRP, '') SER_KEY_GRP, CASE WHEN @ewa_lang = 'enus' THEN CASE WHEN ISNULL(SER_KEY_NAME_EN,'') = '' THEN SER_KEY_NAME ELSE SER_KEY_NAME_EN END ELSE SER_KEY_NAME END SER_KEY_NAME, CASE WHEN @ewa_lang = 'enus' THEN SER_KEY_REMARK_en ELSE SER_KEY_REMARK END SER_KEY_REMARK, SER_KEY_DEF, SER_KEY_EX3, bt.BAS_TAG_PARA1, bt.BAS_TAG_PARA2, bt.BAS_TAG_PARA3, bt.BAS_TAG_PARA4, bt.BAS_TAG_PARA5, bt.BAS_TAG_PARA6 FROM SER_KEY a INNER JOIN ser_keys b ON a.SER_KEY_ID = b.id LEFT JOIN bas_tag bt ON a.SER_KEY_EX3 = bt.bas_tag WHERE SER_KEY_STATUS = 'USED' ORDER BY SER_KEY_GRP, SER_KEY_NAME;
SELECT B.SUP_NAME, B.SUP_NAME_EN, B.SUP_ID FROM SUP_MAIN B WHERE SUP_ID IN ( SELECT DISTINCT SUP_ID AS id FROM SER_CONN A INNER JOIN ENQ_JNY_CACHE_CITYS b ON a.CITY_ID = b.CITY_ID AND b.enq_jny_id = @enq_jny_id AND a.own_sup_id = @G_SUP_ID ) -- 服务下的供应商信息 ;
-- 数量逻辑 SELECT SER_KEY_ID, SER_LGC_NUM0, SER_LGC_NUM1, SER_LGC_DY FROM SER_KEY_LOGIC WHERE SUP_ID = @G_SUP_ID AND SER_LGC_NUM0 >= @NUMS;
-- 已经保存的预算数据 SELECT A.SER_ID, A.ENQ_JNY_SER_SUB_ID, A.ser_conn_id, B.SUP_ID AS sup_id, A.sup_down_id, a.sub_num, b.SER_KEY0, b.SER_KEY1, b.SER_KEY2, b.CITY_ID, a.enq_jny_price, a.ENQ_JNY_SER_REMARK FROM enq_jny_ser_sub a INNER JOIN enq_jny ej ON a.ENQ_JNY_ID = ej.ENQ_JNY_ID INNER JOIN ENQ_OP_MAIN_SUB c ON a.SER_KEY0 = c.SER_KEY0 AND a.SER_KEY1 = c.SER_KEY1 AND a.SER_KEY2 = c.SER_KEY2 AND a.ser_CITY_ID = c.ser_CITY_ID AND c.SUP_DOWN_ID = @G_SUP_ID AND c.FRO_ENQ_JNY_DATE = ej.ENQ_JNY_DATE INNER JOIN ser_conn b ON a.SER_KEY0 = b.SER_KEY0 AND a.SER_KEY1 = b.SER_KEY1 AND a.SER_KEY2 = b.SER_KEY2 AND a.ser_CITY_ID = b.CITY_ID AND a.SUP_DOWN_ID = b.SUP_ID AND b.OWN_SUP_ID = c.SUP_ID -- 询价单的上游供应商 WHERE c.ENQ_OP_ID = @ENQ_OP_ID AND a.ENQ_JNY_ID = @ENQ_JNY_ID;
-- 货币信息 SELECT COIN_ID, COIN_NAME, COIN_KEY FROM SYS_COIN ;

SELECT case when gm.GRP_STA='SCM_GRP_STA_UNENQ' then '已成团不能修改' 
        else '审批流程已到等待客户确认，不能修改' end EWA_ERR_OUT
from ENQ_MAIN em 
	inner join GRP_MAIN gm on em.GRP_ID=gm.GRP_ID
where em.ENQ_ID=@ENQ_ID
	AND (em.FLOW_STATE IN ('ENQ_END', 'ENQ_CONTRACT_VALID','ENQ_CUS_YES') or gm.GRP_STA='SCM_GRP_STA_UNENQ')
	-- and gm.GRP_RUN_MODEL='GRP_RUN_SINGLE' -- 散拼可以改，要改航班和日期，2025-01-22，吕国芳
;

EXEC PR_ENQ_JNY_BAT_ADDV4
	@ENQ_ID	 , 	        -- 询价单编号 ENQ_ID
	@ENQ_JNY_ID ,       -- 日程编号 ENQ_JNY_ID
	@GRP_ID ,           -- 团编号 GRP_ID
	@TRAFFIC,           -- 运输方式 TRAFFIC
	@JNY_CATEGORY ,     -- 日程类型 JNY_CATEGORY
	@ENQ_JNY_DAY ,      -- 天编号 ENQ_JNY_DAY
	@ENQ_JNY_DATE ,     -- 日期 ENQ_JNY_DATE
	@F_ADD ,            -- 出发城市 F_ADD
	@TO_ADD ,           -- 到达城市 TO_ADD
	@TO_ADD2 ,          -- 到达城市2 TO_ADD2
	@CITY_ID ,          -- 居住地 CITY_ID
	@DAYS ,             -- 增加天数 DAYS
	@ENQ_JNY_CONTENT ,  -- 备注 ENQ_JNY_CONTENT
	@SER_CONN_IDS ,     -- 服务编号 SER_CONN_IDS
	@G_ADM_ID ,         -- 管理员 G_ADM_ID
	@G_SUP_ID ,         -- 供应商编号 G_SUP_ID
	@DESS,              -- 描述 DESS
    @SER_NUMS,          -- 每种服务数量 SER_NUMS
    @ENQ_JNY_SER_SUB_IDS, -- 已经存在的服务细节变号 ENQ_JNY_SER_SUB_IDS
    null, -- ENQ_MAIN_LOG.EML_ID, 记录编号，内部调用（PR_ENQ_MAIN_INFO），不存在的话自动创建
    @tmp_rids -- 用于关联enq_jny_day的数据
;

SELECT TOP 1 ENQ_JNY_ID FROM ENQ_JNY
where ENQ_ID=@ENQ_ID
    and ENQ_JNY_DATE=@ENQ_JNY_DATE
    and ENQ_JNY_DAY=@ENQ_JNY_DAY
    and ADM_ID=@G_ADM_ID
    and @ENQ_JNY_ID is null
order by ENQ_JNY_ID desc
;

UPDATE ENQ_JNY 
set MEAL_ID=@MEAL_ID,
    ENQ_JNY_CONTENT_EN=@ENQ_JNY_CONTENT_EN
WHERE ENQ_JNY_ID=@ENQ_JNY_ID
;

-- ; select enq_jny_id AS ID1, B.GRP_ID AS GID1 from enq_jny A INNER JOIN ENQ_MAIN B ON A.enq_id=B.enq_id where A.enq_id=@enq_id and ENQ_JNY_DATE = @ENQ_JNY_DATE and ENQ_JNY_DAY=@ENQ_JNY_DAY and A.sup_id = @g_sup_id;
UPDATE enq_jny SET CAMP_CLASS_TAG = @CAMP_CLASS_TAG , CAMP_STAY_IN = @CAMP_STAY_IN WHERE enq_jny_id =@ID1;
-- 入营日期 UPDATE GRP_MAIN SET GRP_CAMP_BEGIN_DATE = @ENQ_JNY_DATE WHERE @CAMP_CLASS_TAG='CAMP_CLASS_CHECKIN' AND GRP_CAMP_SET_STATUS IS NULL -- 如果值= CAMP_SETTED 表示营地已经设置了 AND GRP_ID = @GID1;
-- 出营日期 UPDATE GRP_MAIN SET GRP_CAMP_END_DATE = @ENQ_JNY_DATE WHERE @CAMP_CLASS_TAG='CAMP_CLASS_CHECKOUT' AND GRP_CAMP_SET_STATUS IS NULL -- 如果值= CAMP_SETTED 表示营地已经设置了 AND GRP_ID = @GID1

