        var s = document.createElement('script');
        s.src = "/static/prj/pf2023/js/2026-enq-jny-design.js?r=" + Math.random();
        s.type = 'text/javascript';
        $("body").append(s);

        const t = setInterval(() => {
            if (!window.enqJnyDesign2026) {
                return;
            }
            window.clearInterval(t);
            window.enqJnyDesign = new enqJnyDesign2026();
            window.ShowTab = function(obj) {
                enqJnyDesign.ShowTab(obj);
            };
            window.copyRow = function(obj) {
                enqJnyDesign.copyRow(obj);
            };
        }, 10);
    } else {
        window.enqJnyDesign = new enqJnyDesign2026();
    }
})();

