function add_to_camp() {
    var x = "business/camp/camp.xml";
    var i = "CAMP_GRP_CONN.Frame.NewModify";
    var p = "EWA_MTYPE=N&GRP_ID=@GRP_ID";
    EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', x, i, false, p);
}

function modify_in_camp(paras) {
    var x = "business/camp/camp.xml";
    var i = "CAMP_GRP_CONN.Frame.NewModify";
    var p = "EWA_MTYPE=M&GRP_ID=@GRP_ID&" + paras;
    EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', x, i, false, p);
}


EWA.F.FOS["@sys_frame_unid"].batModify = function() {
    let ids = [];
    let id = -1;
    var tb = $('#EWA_LF_@sys_frame_unid');
    $("#EWA_LF_@sys_frame_unid>tbody>tr>td>input[name='ENQ_JNY_ID']:checked").each(function() {
        ids.push($(this).val());
    });
    let paras = "ENQ_ID=@ENQ_ID&ENQ_JNY_ID_FROM=" + ids[0];
    if (ids.length > 0) {
        paras += "&ENQ_JNY_IDS=" + ids.join(",");
    }
    EWA.UI.Dialog.OpenReloadClose("@sys_frame_unid", "/business/enq/enqJnyDesign.xml", "ENQ_JNY.F.batModify", false, paras);
}

EWA.F.FOS["@sys_frame_unid"].batDelete = function() {
    let u1 = this.getUrlClass();
    u1.RemoveEwa();
    u1.AddParameter("EWA_WIDTH","1000px");
    u1.AddParameter("EWA_HEIGHT","500px");
    u1.AddParameter("EWA_IN_DIALOG","1");
    let paras=u1.GetParas();
    EWA.UI.Dialog.OpenFrame("@sys_frame_unid","@XMLNAME","2025_ENQ_JNY.Lf.M_FOR_DELETE",false,paras);
}

