// 添加日程,添加完成后延迟刷新列表并再次打开添加窗口
EWA.F.FOS["@sys_frame_unid"].enq_jny_canup1 = function() {
    var u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
    u1.AddParameter("ewa_action", "GetState");
    u1.AddParameter("ewa_ajax", "json");

    var u = u1.GetUrl();
    $J(u, function(str) {
        var p = "EWA_MTYPE=N&enq_id=@enq_id&grp_id=@grp_id&admtype=0&nums=";
        let nums = "@nums";
        if (!nums || nums == "0") {
            nums = "20";
        }
        p += nums;
        if ('@t' == '10' && str[0].FLOW_STATE == 'ENQ_STAR') {
            EWA.UI.Dialog.OpenReloadClose('NEW_@SYS_FRAME_UNID', '@XMLNAME', '2025_ENQ_JNY.F.N', false, p);
        } else if ('@t' != '10' && (str[0].FLOW_STATE == 'ENQ_STAR' || str[0].FLOW_STATE == 'ENQ_OP' ||
                str[0].FLOW_STATE == 'ENQ_ING' || str[0].FLOW_STATE == 'ENQ_JDM_CHK' || '@t' == '12')) {
            EWA.UI.Dialog.OpenReloadClose('NEW_@SYS_FRAME_UNID', '@XMLNAME', '2025_ENQ_JNY.F.N', false, p);
        } else {
            alert('领导审核完毕，无法变更行程内容！');
        }
    });
};
