    ewa.AddPreRowCheck = function(tr, key, evt) {
        if (evt.target.tagName == 'A' || evt.target.tagName == 'IMG') {
            return false;
        }
        if ($(evt.target).hasClass("ewa-col-ENQ_JNY_ID")) {
