    ewa.AddPreRowCloseBeforeEvent = function(frameUnid, tr, aid, prevTr, evt) {
        $(tr).removeClass('hidden-detail');
    };
    ewa.AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        if (ewa.__last_tr) {
            $(ewa.__last_tr).removeClass('hidden-detail')
        }
        ewa.__last_tr = tr;
        $(tr).addClass('hidden-detail')
        var cnt_td = newTr.cells[0]; //新行的td
        var u1;
        var isIframe = false;
        var iframeWidth;
        let tag = evt.target.getAttribute('tag');
        if (tag == 'reception') {
            if ('SER_TAG_CAMP' == evt.target.getAttribute('ser_tag')) {
                // 营地课程安排
                var f_width = $(newTr.cells[0]).width();
                if (f_width > 1300) {
                    f_width = 1300;
                }
                iframeWidth = f_width;
                var objtr = $(evt.target).parentsUntil('tbody').last();
                var rq = objtr.find("#ENQ_JNY_DATE").attr("title").replace(/\-/ig, '');
                u1 = new EWA_UrlClass("@EWA.CP/robert/r_camp_schedule_operation.jsp?" + $U());
                u1.AddParameter("rq", rq);
                u1.AddParameter("ENQ_JNY_DATE", rq);
                u1.AddParameter("GRP_JNY_DATE", rq);
                u1.AddParameter("method", "query");
                u1.AddParameter("noenq", "1");
                u1.AddParameter("f_width", f_width);
                isIframe = true;
            } else {
                u1 = new EWA_UrlClass("@EWA.CP/robert/ewa.jsp?XMLNAME=business/group/grp.xml&ITEMNAME=RECEPTION_NOTICE_APP");
            }
            u1.AddParameter("from_unid", "@SYS_FRAME_UNID");
        } else if (tag == 'send_setting') {
            u1 = new EWA_UrlClass("@EWA.CP/robert/ewa.jsp?XMLNAME=business/group/grp.xml&ITEMNAME=GRP_GO_NOTICE&" + $U());
            u1.AddParameter("from_unid", "@SYS_FRAME_UNID");
            u1.AddParameter("LAST_DAY", 0);
        } else if (tag == 'pickup_setting') {
            u1 = new EWA_UrlClass("@EWA.CP/robert/ewa.jsp?XMLNAME=business/group/grp.xml&ITEMNAME=GRP_GO_NOTICE&" + $U());
            u1.AddParameter("from_unid", "@SYS_FRAME_UNID");
            u1.AddParameter("LAST_DAY", 1);
        } else if (tag == 'ser') {
            u1 = new EWA_UrlClass("@EWA.CP/robert/ewa.jsp?XMLNAME=business/group/grp.xml&ITEMNAME=ENQ_JNY_SER_SUB.Lf.V&" + $U());
            u1.AddParameter("from_unid", "@SYS_FRAME_UNID");
            u1.AddParameter("no_day", "1");
        } else if ("@T" == "12" || window.location.href.indexOf("grp-index-2025.jsp") > 0 || $("#enable_prof_design:checked").length > 0) {
            tag = 'enq_jny_f_nm';
            var p = 'EWA_SKIP_TEST1=1&EWA_MTYPE=M&ENQ_JNY_ID=' + key + '&' + $U();
            var u = '@EWA.CP/ewa?XMLNAME=@XMLNAME&ITEMNAME=2025_ENQ_JNY.F.NM';
            u += '&from_pid=@SYS_FRAME_UNID&hide=@hide&' + p;
            u1 = new EWA_UrlClass(u);
        } else {
            tag = 'enq_jny_f_nm';
            var p = 'EWA_SKIP_TEST1=1&EWA_MTYPE=M&ENQ_JNY_ID=' + key + '&' + $U();
            var u = '@EWA.CP/ewa?XMLNAME=@XMLNAME&ITEMNAME=2025_ENQ_JNY.F.NM';
            u += '&from_pid=@SYS_FRAME_UNID&hide=@hide&' + p;
            u1 = new EWA_UrlClass(u);
        }
        $(cnt_td).css('padding', 0);
        u1.AddParameter("enq_jny_id", key);
        u1.AddParameter("enq_id", "@enq_id");
        var ajax_url = u1.GetUrl();
        if (isIframe) {
            var html = "<iframe src='" + ajax_url + "' frameborder=0 width=100% height=570></iframe>";
            if (iframeWidth) {
                html = "<div style='width:" + iframeWidth + "; margin:auto'>" + html + "</div>";
            }
            $(cnt_td).html(html);
        } else {
            var tmpId = cnt_td.id + '_1';
            var box = "<div id='" + tmpId + "' style='width:860px;margin:auto'></div>";
            if (tag == 'enq_jny_f_nm') {
                box = "<div id='" + tmpId + "' style='min-width:1299px;width:100%;margin:auto'></div>";
            }
            box = $(box);
            box.css('padding', '10px 10px').css('background', '#eee').css('box-sizing', 'border-box');
            $(cnt_td).html(box);
            $Install(ajax_url, tmpId, function() {
                // var top = $(cnt_td).offset().top - 50;
                // $('body').animate({
                //     scrollTop: top
                // }, 300);
                // tr.scrollIntoView({
                //     behavior: 'smooth',
                //     block: 'start'
                // });
                scrollToWithOffset(tr,42);
            });
        }
    });

    function scrollToWithOffset(el, offset = 0) {
        const rect = el.getBoundingClientRect();
        const top = rect.top + window.pageYOffset - offset;

        window.scrollTo({
            top,
            behavior: 'smooth'
        });
    }
    ewa.ext_trans_content = async function(isPrint) {
        if (!window.confirm(isEn ? 'Translate all?' : "确定要翻译全部的行程说明吗?")) {
            return;
        }
        let running = true;
        $Tip(isEn ? 'Translation in progress...' : "翻译中，请等待...", function() {
            return !running;
        });

        let trans = new EWA_UT_TRANS();
        let cnt_en;
        let rows = getObj(">tbody>tr.ewa-lf-data-row");
        let u1 = ewa.getUrlClass();
        u1.RemoveEwa();
        u1.AddParameter("XMLNAME", "@XMLNAME");
        u1.AddParameter("ITEMNAME", "@ITEMNAME");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("ewa_action", "upContentEn");
        u1.AddParameter("ENQ_ID", "@ENQ_ID");
        let upUrl = u1.GetUrl();
        for (let i = 0; i < rows.length; i++) {
            let row = rows.eq(i);
            let cnt = row.find("#ENQ_JNY_CONTENT").html().trim();
            if (!cnt) {
                continue;
            }
            await new Promise((resolve) => {
                trans.TransToEn(cnt, row.find("#ENQ_JNY_CONTENT_EN")[0]);
                let t = window.setInterval(() => {
                    if (!trans.IsRun) {
                        window.clearInterval(t);
                        return resolve();
                    }
                }, 100);
            });
            let cntEn = row.find("#ENQ_JNY_CONTENT_EN").html().trim().replace(/<br>/ig, '\n');
            let data = {
                "ENQ_JNY_CONTENT_EN": cntEn,
                "ENQ_JNY_ID": row.attr("EWA_KEY")
            };
            await new Promise((resolve) => {
                $JP(upUrl, data, function() {
                    return resolve();
                });
            });
        }
        running = false;
        if (isPrint) {
            ewa.ext_printItinerary(true, true);
        }
    }
