Set.Sql:
DELETE FROM ENQ_JNY WHERE ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

delete from ENQ_JNY_SER where ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

delete from ENQ_JNY_SER_SUB where ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID;

exec PR_ENQ_FEE @enq_id;

exec PR_ENQ_TO_PRICE @ENQ_ID;

UPDATE  ENQ_JNY SET ENQ_JNY_FORM_ID = -1 -- 借用， 0表示删除
    WHERE ENQ_JNY_ID = @ENQ_JNY_ID AND SUP_ID=@G_SUP_ID
;

delete from ENQ_JNY_SER where ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY 
        where ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id) 
    AND SUP_ID=@G_SUP_ID;

delete from ENQ_JNY_SER_SUB 
where ENQ_JNY_ID in (select ENQ_JNY_ID from ENQ_JNY 
        where ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id)
    AND SUP_ID=@G_SUP_ID;

DELETE FROM ENQ_JNY WHERE ENQ_JNY_ID in (@ids_split) and enq_id=@enq_id AND SUP_ID=@G_SUP_ID;

exec PR_ENQ_FEE @enq_id;

exec PR_ENQ_TO_PRICE @ENQ_ID;

select 1 DEL_OK;

