    ewa.copyJs = function() {
        return navigator.clipboard.writeText(ewa.ctripJs)
            .then(() => {
                $Tip('脚本复制完成');
                checkCtripData();
                return true;
            })
            .catch(err => {
                alert('Copy failed:', err);
            });
    };

    function checkCtripData() {
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "getCtripFlightData");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("ref_tag", ewa.ctripRefTag);

        let u = u1.GetUrl();

        const t = window.setInterval(() => {
            // 窗口关闭了
            if($('#dialog_ctrip_'+ewa.ctripRefTag).length == 0){
                 window.clearInterval(t);
                 return;
            }
            $J1(u, function(rst) {
                if (rst.length == 0) {
                    return;
                }
                window.clearInterval(t);
                console.log(rst[0]);
            });
        }, 1000);
    }
    ewa.ext_addFlightFromCtrip = function() {
        ewa.ctripRefTag = crypto.randomUUID();
        const url = "/pf2023/back_admin/apis/fetch-flight-info-from-ctrip-create-js.jsp?ref_tag=" + ewa.ctripRefTag;
        $J(url, (rst) => {
            if (!rst.RST) {
                alert(rst.ERR);
                return;
            }
            ewa.ctripJs = rst.JS;
            const html = `<div id='dialog_ctrip_${ewa.ctripRefTag}'>
                    <h1><a href="${rst.URL}" target=_blank>第一步，点击打开携程</a></h1>
                    <h1>第二步，选择航班，到订单界面</h1>
                    <h1>第三步，打开浏览器“检查”窗口</h1>
                    <h1>第四步，粘贴代码<a class='copy' onclick="EWA.F.FOS['@sys_frame_unid'].copyJs()">点击复制</a></h1>
                  </div>`;
            $DialogHtml(html, '', 600);
        });
    };

    let head = "@head" * 1; //领队
    let num = "@num" * 1; //人数
    const nums = "@nums" * 1; // 领队+人数
    if(head == 0){
        num = nums;
    }
    console.log(head, num, nums);
    const enq_jny_day_id = "@enq_jny_day_id";
    const fromLfTable = $('#EWA_LF_' + '@from_unid');
    const servicesLf = fromLfTable.parentsUntil('.z-tab').last().next().find('.ewa-lf-frame'); // div.services
    const servicesLfOld = fromLfTable.parentsUntil('.z-tab').last().next().next().find('.ewa-lf-frame'); // div.services

    const map = {
        "ewa-col-SER_ID": "ewa-col-SER_NAME",
        "ewa-col-SER_PRICE": "ewa-col-SER_PRICE",
        "ewa-col-COIN_ID": "ewa-col-COIN",
        "ewa-col-SUB_NUM": "ewa-col-SUB_NUM",
        "ewa-col-TOTAL": "ewa-col-TOTAL",
        "ewa-col-CITY_NAME": "ewa-col-city_name",
        "ewa-col-TAG_NAME0": "SS",
        "ewa-col-TAG_NAME1": "SS",
        "ewa-col-TAG_NAME2": "SS",
        "ewa-col-TAG_NAME3": "SS",
        "ewa-col-TAG_NAME4": "SS",
        "ewa-col-TAG_NAME5": "SS",
        "ewa-col-TAG_NAME6": "SS",
        "ewa-col-TAG_NAME7": "SS",
        "ewa-col-TAG_NAME8": "SS",
        "ewa-col-TAG_NAME9": "SS",
        "ewa-col-TAG_NAME10": "SS",
        "ewa-col-TAG_NAME11": "SS",
        "ewa-col-SUPPLY_SUP_NAME": "ewa-col-SA",
        "ewa-col-PROVIDER_SUP_NAME": "ewa-col-SP",
    };
    ewa.ext_select = function(obj, skipFlightSetDate) {
        const trHeader = getObj('.ewa-lf-header');
        const tr = $(obj).parent().parent();

        if('@ser_id' == '1' && !skipFlightSetDate){ 
            // 打开机票选择
            const url = new EWA_UrlClass(ewa.Url);
            const rid = EWA_Utils.tempId('obj_');
            $(obj).attr('obj_rid', rid);
            url.AddParameter("itemname","2025_ENQ_JNY_SER_SUB_FLIGHT.LF.setDate")
            url.AddParameter("ser_conn_id", tr[0].dataset.serConnId);
            url.AddParameter("from_unid_1", "@sys_frame_unid");
            url.AddParameter('obj_rid' , rid);
            url.AddParameter('new_setting', 1);
            url.AddParameter('enq_jny_ids', tr[0].dataset.enqJnyIds);
            ewa.flightSetDateDia = $DialogInstall(url, null, 667);
            return;
        }

        const clone = tr.clone(); //显示用
        const clone1 = tr.clone(); //刷新用

        const serId = tr[0].dataset.serId;
        const price = tr[0].dataset.serPrice * 1;

        const names = tagNames[serId];
        const numExp = clone.find('.ewa-col-SUB_NUM').text().replace('@' + 'HEAD', head).replace('@' + 'NUM', num);
        const subNum = Math.round(eval(numExp));
        const total = Math.round(subNum * price);

        const newEwaKey = EWA_Utils.tempId('new_');
        clone1.attr('ewa_key', newEwaKey);
        clone1.attr('data-sub-num', subNum);
        clone1.attr('data-enq-jny-ser-sub-tmp-rid', enq_jny_day_id);
        clone1.attr('onmouseover', 'EWA.F.FOS["' + servicesLf.attr('id').replace('EWA_LF_', '') + '"].MOver(this,event)');
        clone1.find('.ewa-col-SUB_NUM span').text(subNum);
        if ("@selected_enq_jny_ser_sub_id") { //修改模式
            clone1.attr('ewa_key', "@selected_enq_jny_ser_sub_id");
            clone1.attr('data-enq-jny-ser-sub-id', "@selected_enq_jny_ser_sub_id");
            clone1.attr('show_type', 'type-modify');
            servicesLf.find('tr[ewa_key="@selected_enq_jny_ser_sub_id"]').remove();
            servicesLfOld.find('tr[ewa_key="@selected_enq_jny_ser_sub_id"]').remove();
        } else {
            clone1.attr('show_type', 'type-new');
        }
        servicesLf.append(clone1);

        if ("@selected_enq_jny_ser_sub_id") { //修改模式
            fromLfTable.find('.ewa-col-SER_NAME[data-enq-jny-ser-sub-id="@selected_enq_jny_ser_sub_id"]').parent().remove();
            clone.attr('ewa_key', "@selected_enq_jny_ser_sub_id");
            clone.attr('data-enq-jny-ser-sub-id', "@selected_enq_jny_ser_sub_id");
            clone.addClass('type-modify')
        } else {
            clone.addClass('type-new');
            clone.attr("tmp_ser_sub_id", newEwaKey);
        }
        clone.attr('data-enq-jny-ser-sub-tmp-rid', enq_jny_day_id);
        clone.find('.ewa-col-SUB_NUM').text(subNum);
        clone.append('<td class="ewa-col-TOTAL">' + total + '</td>');

        EWA.F.FOS["@from_unid"].showDataInRow(clone, trHeader, "@enq_jny_day_id", map);
        if(!"@multi_selected"){ //单次添加，关闭窗口
            window.seviceSelectDialog.Close();
            window.seviceSelectDialog = null;
        } else {
            $Tip('增加完毕，请继续添加服务');
        }
    }

    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }

    // 重命名和重排TAG顺序
    function renameAndReorderCols() {
        let box = $("#EWA_SEARCH_ITEM_@sys_frame_unid");
        let obj = box.find(".ewa-ref-SER_ID select");
        const serId = "@show_in_jsp" ? "@ser_id" : obj.val();

        if (!serId) {
            return;
        }
        let names = tagNames[serId];

        // 先隐藏没用的列
        let forTags = $J2MAP(names, 'SER_TAG_FOR_TAG_NAME');
        for (let i = 0; i < 12; i++) {
            let tagId = "TAG_NAME" + i;
            if (!forTags[tagId]) {
                getObj('.ewa-col-' + tagId).hide();
            } else {
                getObj('.ewa-col-' + tagId).show();
            }
        }

        // 重命名表头, 第二列绑定修改
        let tagCols = [];
        let isSame = true;
        for (let i = 0; i < names.length; i++) {
            const name = names[i];
            let tagId = name.SER_TAG_FOR_TAG_NAME;
            tagCols.push(tagId);

            const jq = '.ewa-col-' + tagId + '.EWA_TD_H a';

            getObj(jq).text(name.SER_TAG_NAME);



            if (tagId != "TAG_NAME" + i) {
                isSame = false;
            }

            getObj("tr.ewa-lf-data-row .ewa-col-"+tagId+">span").each(function(){
                $(this).addClass("tag-name-ellipsis").attr("title",$(this).text());
            });

        }

        if (isSame) {
            return;
        }

        // 重排tag列
        getObj("tr").each(function() {
            const $tr = $(this);
            const tds = tagCols.map(c => $tr.find(".ewa-col-" + c).detach());
            const $remark = $tr.find(".ewa-col-SER_KEY_REMARK");
            tds.forEach($td => $td.insertBefore($remark));
        });
    }

    // 重命名和重排TAG搜索框顺序
    function renameAndReorderSearchs() {
        let box = $("#EWA_SEARCH_ITEM_@sys_frame_unid");
        let obj = box.find(".ewa-ref-SER_ID select");
        const serId = @SER_ID;
        // if (!serId) {
        //     return;
        // }
        let names = tagNames[serId];

        // 先隐藏没用
        let forTags = $J2MAP(names, 'SER_TAG_FOR_TAG_NAME');
        for (let i = 0; i < 12; i++) {
            let tagId = "TAG_NAME" + i;
            if (!forTags[tagId]) {
                box.find('.ewa-ref-' + tagId).hide();
            } else {
                box.find('.ewa-ref-' + tagId).show();
            }
        }
        let tagCols = [];
        let isSame = true;
        for (let i = 0; i < names.length; i++) {
            const name = names[i];
            let tagId = name.SER_TAG_FOR_TAG_NAME;
            tagCols.push(tagId);

            let b = box.find(".ewa-ref-" + tagId + " td.ewa-lf-search-item-title>nobr>b");
            b.html(name.SER_TAG_NAME + b.find("a").prop("outerHTML"));

            if (tagId != "TAG_NAME" + i) {
                isSame = false;
            }
        }

        if (isSame) {
            return;
        }
        // 重排搜索栏
        const $end = box.find(".ewa-ref-TAG_NAME11").next();
        const $stbs = tagCols.map(c => box.find(".ewa-ref-" + c).detach());
        $stbs.forEach($stb => $stb.insertBefore($end));
    }

    // 自定义固定列
    function customSticky(){
        if(!getObj().is(":visible")){
            //不可见，返回
            return;
        }
        let fs=["CITY_NAME","PROVIDER_SUP_NAME","SER_PRICE","COIN_ID"];
        let left=1;
        for(let i=0;i<fs.length;i++){
            let $tds = getObj(".ewa-col-"+fs[i]);
            let w = $tds.first().width() + 3;
            $tds.addClass("ewa-lf-sticky").css({"left":left+"px","width":w+"px"});
            left+=w;
        }
        getObj().parent().addClass("ewa-lf-sticky-scroll").css({"width":"1185px"});
    }

    EWA.F.FOS["@sys_frame_unid"].customSticky=customSticky;

    // 执行刷新后事件
    function init() {
        ewa.ReloadAfter();
        renameAndReorderSearchs();
        // customSticky();
        if ("@show_in_jsp") {
            return;
        }
    }
    init();
});

