Set.Sql:
-- EWA_SQL_SPLIT_NO -- 【功能】根据行程日ID获取具体出行日期，供后续参数使用 select b.ENQ_JNY_DATE from ENQ_JNY_DAY a -- ENQ_JNY_DAY.ENQ_JNY_DATE不可靠 inner join enq_jny b on a.ENQ_JNY_ID = b.ENQ_JNY_ID where ENQ_JNY_DAY_ID=@ENQ_JNY_DAY_ID;
WITH tmp as ( select 1 a -- 占位用 ) -- ewa_test @ser_id != 1 -- 匹配非机票服务（ser_id ≠ 1）及部分标签型机票服务、直连机票服务 , citys as ( -- 【功能】将输入城市ID扩展为“城市+国家”双重匹配范围 select city_id cid from city where city_id in (@CITYs_split) UNION select country_id from city where city_id in (@CITYs_split) ), ser_conn_ids AS ( SELECT ser_conn_id FROM ser_conn a WHERE own_sup_id = @G_SUP_ID AND CITY_ID in (select cid from citys) AND ser_id != 1 AND A.SER_CONN_STATE = 'USED' AND A.SER_CONN_VER = '2026' and convert(date, @ENQ_JNY_DATE)<=a.SER_CONN_EDATE ) -- ewa_test @ser_id = 1 -- 根据 f_add, TO_ADD, TO_ADD2, CITY_ID,穷举拼接机票格式 出发-抵达城市-日期 -- 【功能】针对机票行程，穷举用户行程中所有可能的（出发,抵达）城市对组合 , flight_citys as ( select b.ENQ_JNY_ID, b.F_ADD departure_city_id, b.TO_ADD arrival_city_id, B.ENQ_JNY_DATE from enq_jny b where b.ENQ_ID = @enq_id and b.TO_ADD >0 and b.TRAFFIC ='AIR' union select b.ENQ_JNY_ID, b.F_ADD departure_city_id, b.TO_ADD2 arrival_city_id, B.ENQ_JNY_DATE from enq_jny b where b.ENQ_ID = @enq_id and b.TO_ADD2 >0 and b.TRAFFIC ='AIR' union select b.ENQ_JNY_ID, b.F_ADD departure_city_id, b.CITY_ID arrival_city_id, B.ENQ_JNY_DATE from enq_jny b where b.ENQ_ID = @enq_id and b.CITY_ID > 0 and b.TRAFFIC ='AIR' union select b.ENQ_JNY_ID, b.TO_ADD departure_city_id, b.TO_ADD2 arrival_city_id, B.ENQ_JNY_DATE from enq_jny b where b.ENQ_ID = @enq_id and B.TO_ADD > 0 and b.TO_ADD2 >0 and b.TRAFFIC ='AIR' union select b.ENQ_JNY_ID, b.TO_ADD departure_city_id, b.CITY_ID arrival_city_id, B.ENQ_JNY_DATE from enq_jny b where b.ENQ_ID = @enq_id and B.TO_ADD > 0 and b.CITY_ID >0 and b.TRAFFIC ='AIR' union select b.ENQ_JNY_ID, b.TO_ADD2 departure_city_id, b.CITY_ID arrival_city_id, B.ENQ_JNY_DATE from enq_jny b where b.ENQ_ID = @enq_id and B.TO_ADD2 > 0 and b.CITY_ID >0 and b.TRAFFIC ='AIR' ), -- 机票的服务 -- 【功能】专用于机票服务（ser_id=1）的精确匹配：要求服务所含航班段与用户行程段完全一一对应 ser_conn_ids as ( -- 【逻辑】仅当服务总航班数 = 与用户行程匹配上的航班数时，才视为有效匹配 SELECT a_main.A_SER_CONN_ID AS ser_conn_id, FLIGHTS, -- 直接在SELECT中拼接，无需外层关联 ISNULL(STUFF(( SELECT ',' + CAST(T1.ENQ_JNY_ID AS VARCHAR(50)) FROM SER_CONN_FLIGHT a INNER JOIN flight_citys T1 ON a.a_d_city_id = T1.departure_city_id AND a.a_a_city_id = T1.arrival_city_id AND T1.ENQ_JNY_DATE BETWEEN a.A_begin AND a.a_end WHERE a.A_SER_CONN_ID = a_main.A_SER_CONN_ID FOR XML PATH(''), TYPE ).value('.', 'NVARCHAR(MAX)'), 1, 1, ''), '') AS ENQ_JNY_IDS FROM ( SELECT a.A_SER_CONN_ID, COUNT(*) FLIGHTS FROM SER_CONN_FLIGHT a WHERE a.A_STATUS = 'USED' GROUP BY a.A_SER_CONN_ID ) a_main WHERE EXISTS ( -- 替代INNER JOIN，验证数量匹配 SELECT 1 FROM SER_CONN_FLIGHT a INNER JOIN flight_citys T1 ON a.a_d_city_id = T1.departure_city_id AND a.a_a_city_id = T1.arrival_city_id AND T1.ENQ_JNY_DATE BETWEEN a.A_begin AND a.a_end WHERE a.A_SER_CONN_ID = a_main.A_SER_CONN_ID HAVING COUNT(*) = a_main.FLIGHTS ) ) -- ewa_test
SELECT a.* FROM ( SELECT A.*, case when a.ser_conn_id = @SELECTED_SER_CONN_ID then 0 else 1 end as ORDER_by_ref, -- ewa_test @ser_id = 1 ser_conn_ids.flights, -- 航班数量 ser_conn_ids.ENQ_JNY_IDS, -- 航班关联的enq_jny_id，用于前段选取日期 -- ewa_test CASE WHEN s.SUB_SUP_ID > 0 THEN -1 WHEN a.PURCHASER_SUP_ID = @G_SUP_ID THEN 0 ELSE 1 END LUKE_SUP, -- 供应商类型排序权重：-1=子供，0=自供，1=他供 CASE WHEN SER_KEY1 > 0 THEN a.SER_KEY_REMARK0 + char(10) + a.SER_KEY_REMARK1 ELSE a.SER_KEY_REMARK0 END SER_KEY_REMARK, -- 动态拼接服务关键备注 b.SER_SCALE -- 服务规模等级 FROM v_ser_conn_detail a INNER JOIN ser_conn_ids ON a.ser_conn_id = ser_conn_ids.ser_conn_id INNER JOIN ser_main b ON a.ser_id = b.ser_id LEFT JOIN ( SELECT DISTINCT SUB_SUP_ID FROM ADM_USER_GRP_SUB augs WHERE SUP_ID = @G_SUP_ID ) s ON a.PURCHASER_SUP_ID = s.SUB_SUP_ID WHERE a.SER_CONN_STATE = 'USED' -- ewa_test @SER_ID > 0 AND A.SER_ID = @SER_ID -- ewa_test ) a WHERE 1 = 1 ORDER BY ORDER_by_ref, LUKE_SUP, -- 优先级：自有 > 子供 > 外供 a.SUPPLY_SUP_ID DESC;
-- ewa_table_name ser_tag_names -- 【系统标记】EWA平台识别：此结果集对应前端表格名为 ser_tag_names SELECT SER_ID, SER_TAG_NAME, SER_TAG_NAME_EN, SER_TAG_FOR_TAG, replace(SER_TAG_FOR_TAG,'TAG','TAG_NAME') SER_TAG_FOR_TAG_NAME -- 动态生成前端绑定字段名 FROM ser_tag WHERE ser_tag = 'NAME' -- ewa_test @SER_ID is not null and SER_ID = @SER_ID -- ewa_test ORDER BY SER_ID, SER_TAG_ORD;

Set.Bottom:
$(function() {
    const ser_tag_names = JSON.parse("@EWA.FRAME.DATA.ser_tag_names");
    const tagMame = $J2MAP1(ser_tag_names, 'SER_ID');
    //console.log(tagMame)
    const parent = getObj().parentsUntil('.z-tab').last().prev(); // div.times

    const ewa = EWA.F.FOS['@SYS_FRAME_UNID'];

    const map = {
        "ewa-col-SER_ID": "ewa-col-SER_NAME",
        "ewa-col-ENQ_JNY_PRICE": "ewa-col-SER_PRICE",
        "ewa-col-COIN_ID": "ewa-col-COIN",
        "ewa-col-SUB_NUM": "ewa-col-SUB_NUM",
        "ewa-col-TOTAL_SUP": "ewa-col-TOTAL",
        "ewa-col-CITY_NAME": "ewa-col-city_name",
        "ewa-col-TAG_NAME0": "SS",
        "ewa-col-TAG_NAME1": "SS",
        "ewa-col-TAG_NAME2": "SS",
        "ewa-col-TAG_NAME3": "SS",
        "ewa-col-TAG_NAME4": "SS",
        "ewa-col-TAG_NAME5": "SS",
        "ewa-col-TAG_NAME6": "SS",
        "ewa-col-TAG_NAME7": "SS",
        "ewa-col-TAG_NAME8": "SS",
        "ewa-col-TAG_NAME9": "SS",
        "ewa-col-TAG_NAME10": "SS",
        "ewa-col-TAG_NAME11": "SS",
        "ewa-col-SUPPLY_SUP_NAME": "ewa-col-SA",
        "ewa-col-PROVIDER_SUP_NAME": "ewa-col-SP",
    };
    function showInTimesRow() {
        const parentFrameUnid = EWA.F.getSubEwas(parent)[0].Id;
        const trHeader = getObj('.ewa-lf-header');
        parent.find('tr.clone-tr-new').remove();
        parent.find('tr').removeAttr('subs_new');
        getObj('tr.ewa-lf-data-row').each(function() {
            const tr = $(this);
            tr.trigger('onmouseover');
            const enqJnyDayId = tr.attr('data-enq-jny-ser-sub-tmp-rid');
            const clone = tr.clone();
            if("@ENQ_JNY_SHOW_MODE" == "2026"){
                EWA.F.FOS[parentFrameUnid].showDataInRow2026(clone, trHeader, enqJnyDayId, map);
            } else {
                EWA.F.FOS[parentFrameUnid].showDataInRow(clone, trHeader, enqJnyDayId, map);
            }
        });
    }
    ewa.ReloadAfter = function() {
        ewa._last_ser_id = null;
        if (parent.length == 0) {
            return;
        }
        if (parent.find('.ewa-lf-frame').length > 0) {
            showInTimesRow();
            return;
        }
        let inc = 0;
        const t = window.setInterval(() => {
            if (parent.find('.ewa-lf-frame').length == 0) {
                inc++;
                if (inc > 1000) {
                    window.clearInterval(t);
                }
                return;
            }
            window.clearInterval(t);
            showInTimesRow();
        }, 50);
    };
    ewa.MOverEvent = function(tr) {
        const serId = tr.dataset.serId;
        if (ewa._last_ser_id == serId) {
            return;
        }
        ewa._last_ser_id = serId;
        const names = tagMame[serId];
        for (const index in names) {
            const name = names[index];
            const idx = name.SER_TAG_FOR_TAG.replace('TAG', '');
            getObj('.ewa-col-TAG_NAME' + idx + '.EWA_TD_H a').text(name.SER_TAG_NAME);
        }
    };


    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }

    // 执行刷新后事件
    function init() {
        ewa.ReloadAfter();
    }
    init();
});

