(function() {
    const ewa = EWA.F.FOS['@SYS_FRAME_UNID'];

    // 添加只读样式，用于隐藏a标签
    let isReadonly="@IS_READONLY";
    if(isReadonly){
        getObj("").addClass("READONLY");
    }

    const ser_tags = JSON.parse("@EWA.FRAME.DATA.ser_tags");
    const serTagMap = $J2MAP(ser_tags, "SER_TAG");
    // console.log(serTagMap)

    const divServices = getObj().parentsUntil('.z-tab').last().next(); // div.services
    const divServicesOld = getObj().parentsUntil('.z-tab').last().next().next(); // div.services

    // 2025_ENQ_JNY.F.NM
    const parentEwa = EWA.F.FOS["@PARENT_EWA_FRAME_UNID"];

    function openSelectServices(enqJnyDayId, relativeSerTags, serId, serConnId, enqJnySerSubId) {
        if(isReadonly){ //只读
            return;    
        }
        console.log('openSelectServices', enqJnyDayId, relativeSerTags, serId, serConnId, enqJnySerSubId);
        const u = new EWA_UrlClass("@ewa.cp/business/group/ser_conn_select.jsp");
        //const u = new EWA_UrlClass(ewa.Url);
        // /business/enq/enqJnyDesign.xml&ITEMNAME=2025_SER_CONN.LF.SELECT&city_id=335
        //u.AddParameter("ITEMNAME", "2025_SER_CONN.LF.SELECT");
        let defaultSerId;
        u.AddParameter('enq_jny_day_id', enqJnyDayId);
        u.AddParameter('from_unid', "@SYS_FRAME_UNID");
        if (relativeSerTags) {
            const arr = relativeSerTags.split(',');
            const serIds = [];
            for (const index in arr) {
                const tag = arr[index];
                if (serTagMap[tag]) {
                    serIds.push(serTagMap[tag].SER_ID);
                }
            }
            if (serIds.length > 0) {
                //u.AddParameter("EWA_SEARCH", "SER_ID[or]" + serIds.join(';'));
                defaultSerId = serIds[0];
            }
        }
        if (serId) {
            //u.AddParameter("EWA_SEARCH", "SER_ID[or]" + serId);
            defaultSerId = serId;
        }
        if (defaultSerId) {
            u.AddParameter("DEFAULT_SER_ID", defaultSerId);
        }
        if (serConnId) {
            u.AddParameter("selected_ser_conn_id", serConnId);
        }
        if (enqJnySerSubId) {
            u.AddParameter("selected_enq_jny_ser_sub_id", enqJnySerSubId);
        }
        // 获取所有城市ids
        const citys = parentEwa.getCitys();
        u.AddParameter("citys_split", citys);
        window.seviceSelectDialog = $DialogInstall(u, '', 1200, 550);
    }
    // 打开机票航班设置界面
    function openFlights(enqJnySerSubId) {
        const u = new EWA_UrlClass(ewa.Url);
        u.AddParameter('ITEMNAME', '2025_ENQ_JNY_SER_SUB_FLIGHT.LF.edit');
        u.AddParameter('enq_jny_ser_sub_id', enqJnySerSubId);
        u.AddParameter('EWA_CELL_ADD_DES', 1);
        window.seviceSelectDialog = $DialogInstall(u, '', 900, 500);
    }
    ewa.setService = function(enqJnyDayId) {
        const tr = getObj("tr[ewa_key=" + enqJnyDayId + "]");
        const relativeSerTags = tr[0].dataset.basTagPara3;
        const defaultSerId = tr[0].dataset.defaultSerId;
        openSelectServices(enqJnyDayId, relativeSerTags, defaultSerId);
    };
    ewa.editService = function(obj) {
        const tr = $(obj).closest('tr');
        const td = tr.find('.ewa-col-SER_NAME');
        const enqJnySerSubId = td.attr('data-enq-jny-ser-sub-id');
        if (!enqJnySerSubId) {
            $Tip("未保存的，请直接删除后再添加");
            return;
        }
        const serId = td[0].dataset.serId;
        const serConnId = td[0].dataset.serConnId;
        const enqJnyDayId = td.attr('data-enq-jny-ser-sub-tmp-rid');
        if (1 == serId) { //flight
            openFlights(enqJnySerSubId)
        } else {
            openSelectServices(enqJnyDayId, null, serId, serConnId, enqJnySerSubId);
        }
    };
    ewa.moveService = function(enqJnyDayId) {

        const u = new EWA_UrlClass(ewa.Url);
        u.AddParameter("ITEMNAME", "2025_ENQ_JNY_SER_SUB.F.move");
        u.AddParameter('enq_jny_day_id', enqJnyDayId);
        u.AddParameter('from_unid', "@SYS_FRAME_UNID");

        window.seviceSelectDialog = $DialogInstall(u, '', 1200, 500);
    };
    ewa.moveServices = function(ids, enqJnyDayId) {
        console.log(ids, enqJnyDayId);
        const ids1 = ids.split(',');
        for (let i = 0; i < ids1.length; i++) {
            const jq = `tr[ewa_key="${ids1[i]}"]`;
            divServicesOld.find(jq)
                .attr('data-enq-jny-ser-sub-tmp-rid', enqJnyDayId);
            divServices.find(jq).attr('data-enq-jny-ser-sub-tmp-rid', enqJnyDayId);
        }

        ewa.reShowServices();

        window.seviceSelectDialog.Close();
        window.seviceSelectDialog = null;
    };
    ewa.changeSubNum = function(input) {
        console.log(input)
        const tr = $(input).parent().parent();
        const ewaKey = tr.find('.ewa-col-SER_NAME').attr('data-enq-jny-ser-sub-id');
        let refTr = divServices.find('tr[ewa_key="' + ewaKey + '"]');
        if (refTr.length == 0) {
            refTr = divServicesOld.find('tr[ewa_key="' + ewaKey + '"]');
        }
        refTr.find('.ewa-col-SUB_NUM span').text(input.value);
        refTr.attr('data-sub-num', input.value);
    };
    ewa.reShowServices = function() {
        getObj('.clone-tr-old,clone-tr-new').remove();
        getObj('.ewa-col-EDJ_REMARK').removeAttr('subs_old').removeAttr('subs_new').removeAttr('rowspan');

        getObj('.ewa-lf-data-row>td').each(function() {
            const td = $(this);
            if (td.find('input[type=button]').length == 0) {
                td.show();
            }
        });
        EWA.F.getSubEwas(divServices)[0].ReloadAfter();
        EWA.F.getSubEwas(divServicesOld)[0].ReloadAfter();
    };
    ewa.removeService = function(obj) {
        $Confirm('您确定要删除么？', '', function() {
            const tr = $(obj).closest('tr');
            let ewaKey = tr.find('.ewa-col-SER_NAME').attr('data-enq-jny-ser-sub-id');
            if (!ewaKey) {
                ewaKey = tr.attr("tmp_ser_sub_id");
            }
            let refTr = divServices.find('tr[ewa_key="' + ewaKey + '"]');
            if (refTr.length == 0) {
                refTr = divServicesOld.find('tr[ewa_key="' + ewaKey + '"]');
            }
            refTr.remove();
            tr.remove();
            ewa.reShowServices();
        });
    };
    ewa.addEnq = function(obj) {
        enqJnyDesign.xj(obj);
    };
    const dataSetMap = ['serexp', 'data-ser-id', 'data-ser-conn-id', 'data-enq-jny-ser-sub-id', 'data-enq-jny-ser-sub-tmp-rid', 'data-sup-id', 'data-provider-sup-id', 'data-ser-conn-state'];

    function setDataset(tr, td) {
        for (let i = 0; i < dataSetMap.length; i++) {
            const name = dataSetMap[i];
            const v = tr.attr(name);
            td.attr(name, v);
            if('data-ser-conn-state' == name){ //删除的服务要显示
                td.parent().addClass(v);
            }
        }
    }
    //重新调整机票展示信息
    function rewriteFlightInfo(enqJnySerSubId, tr) {
        const u = "@ewa.cp/ewa?xmlName=@xmlName&ITEMNAME=2025_ENQ_JNY_SER_SUB_FLIGHT.LF.edit" +
            "&enq_jny_ser_sub_id=" + enqJnySerSubId + '&ewa_ajax=JSON';
        $J1(u, function(rst) {
            const ss = [];
            for (let i = 0; i < rst.length; i++) {
                const flight = rst[i];
                const des = `<div>${i+1}. 日期：${flight.EA_ENQ_JNY_DATE.split(' ')[0]}，
                    航班号：${flight.A_CODE}，${flight.departure_city}-${flight.arrival_city}</div>`;
                ss.push(des);
            }
            const td = tr.find('.ewa-col-services');
            td.find('span[ref_class="ewa-col-TAG_NAME1"]').remove(); //出发城市
            td.find('span[ref_class="ewa-col-TAG_NAME2"]').remove(); //航班
            td.find('span[ref_class="ewa-col-TAG_NAME5"]').remove(); //抵达城市
            td.append(ss.join(''))
            td.attr('title', td.text());
        });
    }

    function copyTr(targetTr, isblank) {
        targetTr.find('td:gt(0)').hide();
        if (!targetTr.attr('set_show')) {
            targetTr.attr('set_show', 1);

            const css1 = {
                display: 'block',
                'text-align': 'left'
            };

            const td = targetTr.find('td:eq(0)');
            td.attr('colspan', 14);
            const text = td.find('a:eq(0)').text();
            td.find('a:eq(0)').removeAttr('onclick').hide();
            td.find('div').css(css1);
            td.find('#EDJ_REMARK>div').append('<span>' + text + '<span>' + targetTr.find('.ewa-col-buts>div>div').html());
        }
        const newTr = targetTr.clone();
        newTr.removeAttr('total-subs');
        if (isblank) {
            newTr.find('.ewa-col-EDJ_REMARK').html("");
        } else {
            newTr.find('.ewa-col-EDJ_REMARK').html(targetTr.find('.ewa-col-buts').html());
            newTr.find('td').each(function() {
                const td = $(this);
                td.attr('colspan', 1).attr('rowspan', 1);
                if (td.find('input[type=button]').length == 0 && !td.hasClass('ewa-col-buts')) {
                    td.show();
                }
            });
            newTr.find('.ewa-col-buts').hide();
        }
        targetTr.after(newTr);
        const ewaKey = targetTr.attr('ewa_key');
        const total = getObj('tr[ewa_key=' + ewaKey + ']').length;
        targetTr.attr('total-subs', total - 2);
        return newTr;
    }
    // 在时程上附加服务，效果不好，停用
    ewa.showDataInRow2026 = function(tr, trHeader, enqJnyDayId, map, isOld) {
        const serId = tr[0].dataset.serId;
        const enqJnySerSubId = tr[0].dataset.enqJnySerSubId;

        let targetTr;
        if (enqJnyDayId) {
            targetTr = getObj('tr[ewa_key=' + enqJnyDayId + ']:eq(0)');
        }
        if (!targetTr || targetTr.length == 0) { //目标行不存在
            targetTr = getObj('tr[data-bas-tag-para3="N/A"]:eq(0)');
            enqJnyDayId = targetTr.attr('ewa_key');
            tr.attr('data-enq-jny-ser-sub-tmp-rid', enqJnyDayId);
        }

        let newTr;
        newTr = copyTr(targetTr);

        newTr.addClass('clone-tr clone-tr' + (isOld ? '-old' : '-new'));
        if (tr.attr("tmp_ser_sub_id")) {
            newTr.attr("tmp_ser_sub_id", tr.attr("tmp_ser_sub_id"));
        }

        const ss = [];
        const ssTitles = [];
        tr.find('td').each(function(index) {
            const td = $(this);
            const text = td.text();

            for (const className in map) {
                const targetClassName = map[className];
                if (!td.hasClass(className)) {
                    continue;
                }
                if ("SS" == targetClassName && text) {
                    // console.log(className, targetClassName)
                    const tdHeader = trHeader[0].cells[index];
                    let des = "<span ref_class='" + className + "'><b>" + $(tdHeader).text() + "</b>: "
                    let html = des + text.replace(/</ig, "&lt;").replace(/"/ig, "&nbsp;") + "</span>";
                    ss.push(html);

                    ssTitles.push($(tdHeader).text() + ':' + text);
                    return;
                }
                const targetTd = newTr.find('.' + targetClassName);
                if (targetClassName == 'ewa-col-SER_NAME') {
                    setDataset(tr, targetTd);

                }
                if (targetClassName == 'ewa-col-SUB_NUM') {
                    const num = Math.round(text);
                    const input = `<input id=SUB_NUM class="EWA_INPUT"
                        onchange="EWA.F.FOS['@sys_frame_unid'].changeSubNum(this)"
                        name=SUB_NUM value="${num}">`;
                    targetTd.html(input);
                } else if (targetClassName == 'ewa-col-ENQ_OP_ID') {
                    targetTd.html(td.html());
                } else {
                    const html = "<span>" + text.replace(/</ig, "&lt;").replace(/"/ig, "&nbsp;") + "</span>";
                    targetTd.html(html).attr('title', text);
                }
                return;
            }
        });
        const siHtml = ss.join("");
        const title = ssTitles.join(", ");
        const tdServices = newTr.find('td.ewa-col-services');
        if (isOld) {
            tdServices.html("<span><i>[旧版]" + siHtml + "</i></span>")
                .attr('title', "[旧版]" + title);
        } else {
            tdServices.html("<span>" + siHtml + "</span>").attr('title', title);
            if (1 == serId) {
                // 改写机票信息
                rewriteFlightInfo(enqJnySerSubId, newTr);
            }
        }
        if(isReadonly){
            newTr.find("input").prop("disabled",true);
        }else{
            tdServices.on('click', function() {
                $(this).parent().find('a.edit-service').trigger('click');
            });
        } 
    };
    // 在时程上附加服务
    ewa.showDataInRow = function(tr, trHeader, enqJnyDayId, map, isOld) {
        //console.log(tr, trHeader, enqJnyDayId, map)
        const serId = tr[0].dataset.serId;
        const enqJnySerSubId = tr[0].dataset.enqJnySerSubId;
        // console.log(serId);

        let targetTr;
        if (enqJnyDayId) {
            targetTr = getObj('tr[ewa_key=' + enqJnyDayId + ']:eq(0)');
        }
        if (!targetTr || targetTr.length == 0) { //目标行不存在
            targetTr = getObj('tr[data-bas-tag-para3="N/A"]:eq(0)');
            enqJnyDayId = targetTr.attr('ewa_key');
            tr.attr('data-enq-jny-ser-sub-tmp-rid', enqJnyDayId);
        }

        targetTr.find('td:gt(0)').hide();

        let subsOld = targetTr.attr('subs_old') || 0;
        let subsNew = targetTr.attr('subs_new') || 0;
        let subs = subsOld * 1 + subsNew * 1;
        let newTr;
        if (0 === subs && 1 == 2) {
            newTr = targetTr;
        } else {
            newTr = targetTr.clone();
            newTr.addClass('clone-tr clone-tr' + (isOld ? '-old' : '-new'));
        }
        if (tr.attr("tmp_ser_sub_id")) {
            newTr.attr("tmp_ser_sub_id", tr.attr("tmp_ser_sub_id"));
        }

        const ss = [];
        const ssTitles = [];
        tr.find('td').each(function(index) {
            const td = $(this);
            const text = td.text();

            for (const className in map) {
                const targetClassName = map[className];
                if (!td.hasClass(className)) {
                    continue;
                }
                if ("SS" == targetClassName && text) {
                    // console.log(className, targetClassName)
                    const tdHeader = trHeader[0].cells[index];
                    let des = "<span ref_class='" + className + "'><b>" + $(tdHeader).text() + "</b>: "
                    let html = des + text.replace(/</ig, "&lt;").replace(/"/ig, "&nbsp;") + "</span>";
                    ss.push(html);

                    ssTitles.push($(tdHeader).text() + ':' + text);
                    return;
                }
                const targetTd = newTr.find('.' + targetClassName);
                if (targetClassName == 'ewa-col-SER_NAME') {
                    setDataset(tr, targetTd);

                }
                if (targetClassName == 'ewa-col-SUB_NUM') {
                    const num = Math.round(text);
                    const input = `<input id=SUB_NUM class="EWA_INPUT"
                        onchange="EWA.F.FOS['@sys_frame_unid'].changeSubNum(this)"
                        name=SUB_NUM value="${num}">`;
                    targetTd.html(input);
                } else if (targetClassName == 'ewa-col-ENQ_OP_ID') {
                    targetTd.html(td.html());
                } else {
                    const html = "<span>" + text.replace(/</ig, "&lt;").replace(/"/ig, "&nbsp;") + "</span>";
                    targetTd.html(html).attr('title', text);
                }
                return;
            }
        });
        newTr.find('td').each(function() {
            const td = $(this);
            if (td.find('input[type=button]').length == 0) {
                td.show();
            }
        });
        const siHtml = ss.join("");
        const title = ssTitles.join(", ");
        const tdServices = newTr.find('td.ewa-col-services');
        let serConnMemo;
        if (isOld) {
            subsOld++;
            targetTr.attr('subs_old', subsOld);
            tdServices.html("<span><i>[旧版]" + siHtml + "</i></span>")
                .attr('title', "[旧版]" + title);
        } else {
            subsNew++;
            targetTr.attr('subs_new', subsNew);
            tdServices.html("<span>" + siHtml + "</span>").attr('title', title);
            if (1 == serId) {
                // 改写机票信息
                rewriteFlightInfo(enqJnySerSubId, newTr);
            }else{
                serConnMemo=tr.attr("data-ser-conn-memo");
            }
        }
        //if (subs > 0) {
        newTr.find('.ewa-col-EDJ_REMARK').remove();
        targetTr.after(newTr);
        //}
        targetTr[0].cells[0].rowSpan = subsOld * 1 + subsNew * 1 + 1;

        if(serConnMemo){
            let scMemo=`<div style='color: #aaa' 
                title='${serConnMemo}'
                onclick='EWA.UI.Msg.ShowInfo(this.innerHTML)'>${serConnMemo}</div>`;
            tdServices.append(scMemo);
        }
        if(isReadonly){
            newTr.find("input").prop("disabled",true);
        }else{
            tdServices.children("span").eq(0).on('click', function() {
                $(this).parent().parent().find('a.edit-service').trigger('click');
            });
        }
    };

    // 导入时程后重新装载日程
    EWA.F.FOS["IMP_@SYS_FRAME_UNID"] = {
        Reload: function() {
            let pUnid = "@PARENT_EWA_FRAME_UNID";
            let url = EWA.F.FOS[pUnid].Url;
            let box = $(".ewa-lf-add-pre-cell>div")[0];
            $Install(url, box);
        }
    };

    // 导入时程
    ewa.ext_importTimes = function() {
        let fromGrpId = "@GRP_ID";
        let toEnqId = "@ENQ_ID";
        let toEnqJnyId = "@ENQ_JNY_ID";
        let paras = `FROM_GRP_ID=${fromGrpId}&TO_ENQ_ID=${toEnqId}&TO_ENQ_JNY_ID=${toEnqJnyId}&IMPORT_TYPES=TIMES`;
        EWA.UI.Dialog.OpenReloadClose('IMP_@SYS_FRAME_UNID', '@xmlName', '2025_ENQ_JNY_SER_SUB.F.import', false, paras);
    }

    // 补全缺少的时程
    ewa.ext_fillMissingJnyDay = function() {
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("EWA_ACTION", "SAct1");
        $J(u1.GetUrl(), function(data) {
            if (data[0].DELETED_NUM != "0") {
                if (window.confirm("同时恢复回收站中的时程吗？")) {
                    u1.AddParameter("Restore", "1");
                }
            }
            u1.AddParameter("EWA_ACTION", "UAct0");
            $J(u1.GetUrl(), function() {
                EWA.F.FOS["IMP_@SYS_FRAME_UNID"].Reload();
            })
        });
    }

    function getObj(exp) {
        return exp ? $('#EWA_LF_@sys_frame_unid').find(exp) : $('#EWA_LF_@sys_frame_unid');
    }
    ewa.ext_AddNew = function() {
        let u1 = new EWA_UrlClass(ewa.Url);
        u1.RemoveEwa();
        u1.AddParameter("EWA_MTYPE", "N");
        u1.AddParameter('ewa_in_dialog', 1);
        let paras = u1.GetParas();
        EWA.UI.Dialog.OpenReloadClose('@SYS_FRAME_UNID', '@xmlName', '2025_ENQ_JNY_DAY.F.Time', false, paras);
    };
    ewa.AddPreRow(function(frameUnid, tr, key, newTr, evt) {
        const cntTd = newTr.cells[0]; //新行的td
        const div = $("<div class='ewa-break'></div>");
        $(cntTd).append(div);

        const u1 = new EWA_UrlClass(this.Url);
        u1.AddParameter("ITEMNAME", "2025_ENQ_JNY_DAY.F.Time");
        u1.AddParameter("EWA_MTYPE", "M");
        u1.AddParameter("ENQ_JNY_DAY_ID", key);
        u1.AddParameter("parent_frame_unid", "@SYS_FRAME_UNID");
        // 通过ajax加载内容
        const ajaxUrl = u1.GetUrl();
        $Install(ajaxUrl, div, function() {
            // console.log('install ok');
        });
    });
    ewa.AddPreRowCheck = function(tr, key, evt) {
        //console.log(tr);
        if ($(tr).hasClass('clone-tr') || tr.dataset.ejdTimeBucket == 'ENQ_TIME_UNDEFINED') {
            return false;
        }
        return true;
    };
    ewa.AddPreRowCloseBeforeEvent = function(frameUnid, cr, key, nr, evt) {
        // TODO 你要做的事情
        console.log('AddPreRowCloseBeforeEvent');
    };

    ewa.AddPreRowCloseEvent = function(frameUnid, tr, key, newTr, evt) {
        // TODO 你要做的事情
        console.log('AddPreRowCloseEvent');
    };
    ewa.ReloadAfter = function(httpReferer) {
        if ("@up_enq_op_id") {
            getObj().addClass('up_enq_op_id')
        }
        getObj().attr('border', 1);
        //this.mergeHeaders('SA', '预算', 7); //合并单元格
        //this.mergeHeaders('ENQ_OP_MAIN', '服务采购', 3); //合并单元格
        console.log(1111)
        getObj('nobr,.ewa-col-EDJ_REMARK').each(function() {
            $(this).attr('title', $(this).text().trim());
        });

        const lfServices = EWA.F.getSubEwas(divServices)[0];
        if (lfServices) {
            // 将服务映射到时间上
            lfServices.ReloadAfter();
        }
        const lfServicesOld = EWA.F.getSubEwas(divServicesOld)[0];
        if (lfServicesOld) {
            // 将服务映射到时间上
            lfServicesOld.ReloadAfter();
        }
        const general = getObj('tr[data-ejd-time-bucket="ENQ_TIME_UNDEFINED"] .ewa-col-EDJ_REMARK');
        general.find('a:eq(0)').each(function() {
            $(this).attr('onclick', '$Tip("不用修改")');
        });
        general.find('a:eq(1)').hide();

        if ("@ENQ_JNY_SHOW_MODE" !== "2026") {
            return;
        }

        getObj('tbody').addClass('mode2026');
        getObj('.ewa-col-buts').hide();
        getObj('tr.ewa-lf-data-row').each(function() {
            const ntr = copyTr($(this), true)
            ntr.addClass('init-copyed', 1);
        });
    };
    // 执行刷新后事件
    function init() {
        ewa.ReloadAfter();
    }
    init();
})();

