Set.Sql:
SELECT '已经关联服务，不能删除' AS ewa_err_out FROM ENQ_JNY_DAY WHERE ENQ_JNY_DAY_ID = @ENQ_JNY_DAY_ID AND EXISTS ( SELECT 1 FROM enq_jny_ser_sub WHERE enq_jny_id = @enq_jny_id AND ENQ_JNY_SER_SUB_TMP_RID = @ENQ_JNY_DAY_ID );
SELECT '默认不能删除' AS ewa_err_out FROM ENQ_JNY_DAY WHERE ENQ_JNY_DAY_ID = @ENQ_JNY_DAY_ID AND EJD_TIME_BUCKET = 'ENQ_TIME_UNDEFINED';
-- 直接物理删除了
DELETE ENQ_JNY_DAY WHERE ENQ_JNY_DAY_ID = @ENQ_JNY_DAY_ID AND SUP_ID = @G_SUP_ID
